INSERT INTO public.photos VALUES (22663, 'Porches Mercado 1979', 'Porches junto al Mercado Central, en el tramo entre la calle de San Blas y la calle de Las Armas (al fondo). Fuente visual: Foto Leonardo Pâ”œآ®rez Obis, donada por â”œأ¼ngel Hernâ”œأ­ndez Mostajo para www.rafaelcastillejo.com', 1979, 1979, 1979, 'Anos 70', 'CASCO HISTâ”œأ´RICO', 41.65608700, -0.88328400, '0101000020E6100000E28FA2CEDC43ECBF562AA8A8FAD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22752472359.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22752472359.webp', 'https://www.flickr.com/photos/zaragozaantigua/22752472359/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22676, 'Calle de San Pablo 1978', 'Imagen capturada durante las obras de restauraciâ”œâ”‚n de la iglesia de San Pablo Apâ”œâ”‚stol acometidas a finales de los aâ”œâ–’os setenta del siglo XX, cuando de la fachada principal fue erradicada la intervenciâ”œâ”‚n que a finales del siglo XVIII habâ”œآ،a aâ”œâ–’adido en piedra un nuevo muro y elementos decorativos tardo-neoclâ”œأ­sicos (pilastras lisas, cornisa superior y hornacinas con jarrones). Esta restauraciâ”œâ”‚n promovida por el Ministerio de la Vivienda pretendâ”œآ،a conferir al conjunto aires (neo) medievales en formas (neo) mudâ”œآ®jares, al gusto de la â”œآ®poca. Fuente visual: AMZ.', 1978, 1978, 1978, 'Anos 70', 'CASCO HISTâ”œأ´RICO', 41.65588600, -0.88609200, '0101000020E610000053E9279CDD5AECBFBFF38B12F4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24870123688.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24870123688.webp', 'https://www.flickr.com/photos/zaragozaantigua/24870123688/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22678, 'General Franco 1978', 'Imagen de la esquinera fachada, recayente a las calles general Franco, y Ramâ”œâ”‚n y Cajal, de la antigua manzana delimitada por las calles Boggiero, Miguel de Ara (izquierda), general Franco, y Ramâ”œâ”‚n y Cajal (derecha). Todo este frontal habitacional, con bajos comerciales, fue derribado poco despuâ”œآ®s. A la izquierda, se intuye ya el derribo consumado del antiguo nâ”¬â•‘ 23 de la calle Miguel de Ara. Estas viviendas, de tres alturas, mâ”œأ­s los bajos, son testimonio de una tipologâ”œآ،a edilicia que ha sido masacrada sin demasiados miramientos en la ciudad, de forma especialmente destacable en la dâ”œآ®cada de los aâ”œâ–’os 70 del pasado siglo XX. Tras los importantes retranqueos realizados para ensanchar las calles de Boggiero, Miguel de Ara, y algo menos la de Ramâ”œâ”‚n y Cajal, la mayor parte de esta manzana perdurâ”œâ”‚ como un despejado y câ”œآ®ntrico solar en el que apenas superviven un par de antiguas viviendas. En 2025 el solar fue edificado. Fuente visual: Gerardo Sancho Ramo, Archivo Municipal Zaragoza-DARA.', 1978, 1978, 1978, 'Anos 70', 'CASCO HISTâ”œأ´RICO', 41.65477500, -0.88596400, '0101000020E6100000F4DDAD2CD159ECBF849ECDAACFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26177207453.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26177207453.webp', 'https://www.flickr.com/photos/zaragozaantigua/26177207453/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22702, 'Calle San Pablo 1978', 'Imagen de la calle de San Pablo, capturada desde la plaza del mismo nombre. A la izquierda, inmediata, queda la iglesia parroquial, a la derecha, el arranque de la calle Miguel de Ara, y al fondo, el principio de la calle de San Pablo desde el despejado panorama que habâ”œآ،a dejado el reciente derribo de la manzana de la calle de las Escuelas Pâ”œآ،as,convertida en parte de la moderna avenida de Câ”œآ®sar Augusto. Fuente visual: amable aportaciâ”œâ”‚n personal de Pablo Valdâ”œآ®s.', 1978, 1978, 1978, 'Anos 70', 'CASCO HISTâ”œأ´RICO', 41.65582500, -0.88573900, '0101000020E6100000F855B950F957ECBF1973D712F2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27471392250.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27471392250.webp', 'https://www.flickr.com/photos/zaragozaantigua/27471392250/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22780, 'Calle de San Blas 1979', 'Imagen capturada en la calle de San Blas del barrio de San Pablo, con una vista parcial del tramo comprendido entre la calle de Aguadores (hacia la derecha) y la plaza de Santo Domingo (hacia la izquierda) centrada en la radical contraposiciâ”œâ”‚n entre el moderno bloque de los nâ”œâ•‘meros 100-102 (derecha), y las antiguas viviendas de los nâ”œâ•‘meros 104 al 124 (izquierda). Mediante importantes y quirâ”œâ•‘rgicos cambios de alineaciâ”œâ”‚n, el Plan de Reforma Interior aplicado supuso el arrasamiento y destrucciâ”œâ”‚n de importantes sectores del tradicional tejido urbano con la excusa del "saneamiento" y ensanchamiento para habilitar aparcamiento en superficie al automâ”œâ”‚vil y mayor superficie para el trâ”œأ­nsito rodado. Eran los tiempos en que estas intervenciones incluyeron, ademâ”œأ­s, los espeluznantes bloques habitacionales de la calle de Santa Lucâ”œآ،a angular con la plaza de Santo Domingo, la destrucciâ”œâ”‚n de buena parte del convento de las Fecetas, et alia. Tiempo despuâ”œآ®s de la realizaciâ”œâ”‚n de esta fotografâ”œآ،a, las parcelas de la izquierda serâ”œآ،an derribadas. Fuente visual: Andalâ”œأ­n, periâ”œâ”‚dico semanal aragonâ”œآ®s, 1979.', 1979, 1979, 1979, 'Anos 70', 'CASCO HISTâ”œأ´RICO', 41.65665100, -0.88774500, '0101000020E61000002A00C6336868ECBF5EF1D4230DD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/37719939034.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/37719939034.webp', 'https://www.flickr.com/photos/zaragozaantigua/37719939034/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22832, 'Rastro del Mercado 1985', 'Foto: Arturo Burgos. Mayo de 1985. El rastro de Zaragoza uno de sus domingos de esplendor, en la avenida de Câ”œآ®sar Augusto, junto al Mercado Central. Ese mismo aâ”œâ–’o serâ”œأ­ trasladado a dos ubicaciones, segâ”œâ•‘n la mercaderâ”œآ،a: los cachivaches, junto a la plaza de toros; la ropa y similares, junto al estadio de fâ”œâ•‘tbol. Fuente: dezaragozaalzierzo.blogspot.com', 1985, 1985, 1985, 'Anos 80', 'CASCO HISTâ”œأ´RICO', 41.65532600, -0.88373600, '0101000020E6100000098849B89047ECBFF81BEDB8E1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14712649239.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14712649239.webp', 'https://www.flickr.com/photos/zaragozaantigua/14712649239/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22845, 'Av. Câ”œآ®sar Augusto aâ”œâ–’os 80', 'Aâ”œâ–’os 80. En Câ”œآ®sar Augusto, entre los chipirones, a la izquierda, del "Chipirâ”œâ”‚n", y los millones de la Agencia urbana 6 "Lanuza", a la derecha, allâ”œآ، estaba "Calzados-Cordelerâ”œآ،a Sebastiâ”œأ­n Sieso", con alpargatas, botas de calzar, persianas, botas de vino, cestas, bolsos, sillas... Llevaba desde 1931 por el barrio, cuando la calle se llamaba de Antonio Pâ”œآ®rez.', 1980, 1980, 1989, 'Anos 80', 'CASCO HISTâ”œأ´RICO', 41.65600800, -0.88323500, '0101000020E610000088D7F50B7643ECBF0AF5F411F8D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15132487785.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15132487785.webp', 'https://www.flickr.com/photos/zaragozaantigua/15132487785/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22854, 'Calle San Pablo aâ”œâ–’os 80', 'Calle de San pablo en los aâ”œâ–’os 80, con su antigua pavimentaciâ”œâ”‚n. A la derecha, calle de Broqueleros. A la izquierda, Echeandâ”œآ،a. Fuente: www.facebook.com/photo.php?fbid=1578893569005540&set=...', 1980, 1980, 1989, 'Anos 80', 'CASCO HISTâ”œأ´RICO', 41.65554800, -0.88449100, '0101000020E61000001B67D311C04DECBFA77A32FFE8D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15479806726.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15479806726.webp', 'https://www.flickr.com/photos/zaragozaantigua/15479806726/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22870, 'Av. Câ”œآ®sar Augusto c.1984', 'Trâ”œأ­fico rodado proveniente del paseo de Echegaray y Caballero, a su paso por el cruce de la calle de San Blas (a la izquierda) con la avenida de Câ”œآ®sar Augusto y la plaza de Lanuza (a la derecha, fuera de plano). Tras las viandantes, el Mercado Central. Fuente: Foto aportada por Javier Peâ”œâ–’a Gonzalvo a Fotos Antiguas de Zaragoza: www.facebook.com/photo.php?fbid=998859546796557&set=o...', 1984, 1984, 1984, 'Anos 80', 'CASCO HISTâ”œأ´RICO', 41.65591000, -0.88340200, '0101000020E61000005E126745D444ECBF478FDFDBF4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15788242195.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15788242195.webp', 'https://www.flickr.com/photos/zaragozaantigua/15788242195/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22902, 'Av. Câ”œآ®sar Augusto 1989', 'Porches junto al Mercado Central, en la avenida Câ”œآ®sar Augusto, esquina con la calle de San Blas (izquierda), el 7 de octubre de 1989. Fuente: "Memoria de las calles de Zaragoza", Juliâ”œأ­n Ruiz Marâ”œآ،n, Librerâ”œآ،a General, 1997.', 1989, 1989, 1989, 'Anos 80', 'CASCO HISTâ”œأ´RICO', 41.65600800, -0.88323500, '0101000020E610000088D7F50B7643ECBF0AF5F411F8D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21351408703.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21351408703.webp', 'https://www.flickr.com/photos/zaragozaantigua/21351408703/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22934, 'El rastro 1985', 'Ilustraciâ”œâ”‚n de Alberto Calvo de 1988, representando el rastro de Zaragoza, situado en la avenida de Câ”œآ®sar Augusto, junto al Mercado Central. En el momento de ser realizado el dibujo, este mercadillo se habâ”œآ،a trasladado a sus dos ubicaciones en la Plaza de Toros y La Romareda. Fuente: Heraldo de Aragâ”œâ”‚n.', 1985, 1985, 1985, 'Anos 80', 'CASCO HISTâ”œأ´RICO', 41.65565200, -0.88359600, '0101000020E61000009A0B5C1E6B46ECBF4CC79C67ECD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31887327236.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31887327236.webp', 'https://www.flickr.com/photos/zaragozaantigua/31887327236/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22175, 'P.â”¬â•‘ de Isabel la Catâ”œâ”‚lica 1955', 'Imagen del tranquilo paseo de Isabel la Catâ”œâ”‚lica, centrada en la gran estructura del Colegio-Residencia de Nuestra Seâ”œâ–’ora del Pilar para Huâ”œآ®rfanos e Hijos del Magisterio. A su izquierda, la monumental Residencia Sanitaria Josâ”œآ® Antonio. En primer plano, el camino de hierro habilitado para servicio de la tranviaria lâ”œآ،nea 15, o de Casablanca. Fuente visual: Foto Estudio Coyne, AHPZ.', 1955, 1955, 1955, 'Anos 50', 'UNIVERSIDAD', 41.63401800, -0.90284100, '0101000020E61000002C9D0FCF12E4ECBFA489778027D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31551895531.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31551895531.webp', 'https://www.flickr.com/photos/zaragozaantigua/31551895531/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22960, 'Calle de San Blas c.1981', 'Imagen capturada en la plaza de San Pablo y centrada en el inmediato tramo de la calle de San Blas, con el aspecto que entonces esta presentaba, alternando antiguos inmuebles y solares de los ya derribados, de su tramo comprendido entre los nâ”œâ•‘meros 62 (a la derecha)-74 (hacia el fondo). En primer tâ”œآ®rmino y a la izquierda, el esquinero inmueble del nâ”¬â•‘ 4 de la plaza de San Pablo. Todos los edificios que aquâ”œآ، aparecen luego fueron integralmente intervenidos, y sobre los solares se construyeron nuevas estructuras habitacionales, que junto con una preceptiva urbanizaciâ”œâ”‚n impulsada por el Ayuntamiento le dio un nuevo aspecto a esta tradicional zona del barrio de San Pablo.', 1981, 1981, 1981, 'Anos 80', 'CASCO HISTâ”œأ´RICO', 41.65645100, -0.88639300, '0101000020E610000010E84CDA545DECBF97361C9606D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52124550314.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52124550314.webp', 'https://www.flickr.com/photos/zaragozaantigua/52124550314/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22963, 'Avda. de Câ”œآ®sar Augusto 1985', 'Imagen capturada en la avenida de Câ”œآ®sar Augusto a espaldas del Mercado Lanuza y centrada en el solar esquinero con la calle de San Blas donde estuviera el inmueble que tradicionalmente acogiâ”œâ”‚ el comercio textil "El Pequeâ”œâ–’o Catalâ”œأ­n", ademâ”œأ­s de un par de casas en el arranque de la calle de San Blas, una de las cuales tras ser derribada dejâ”œâ”‚ su impronta en la medianera del edificio del nâ”¬â•‘ 7-9, a la derecha de la imagen. Del edificio del comercio textil perduraba aquâ”œآ، apenas el arranque del grueso pilar de uno de sus soportales, sobre el que aparece sentado un ciudadano en el centro de la foto. A finales del siglo XX y principios del XXI esta manzana hasta la calle de San Pablo adquirirâ”œآ،a su actual aspecto, mediante la integral construcciâ”œâ”‚n de inmuebles de nueva planta y conservando restaurada la fachada del abalconado edificio del nâ”¬â•‘ 37 (actual nâ”¬â•‘ 73), a la izquierda. En primer tâ”œآ®rmino, convivencia de firmes: el antiguo adoquinado de la calle de San Blas, y el moderno asfaltado de la avenida de Câ”œآ®sar Augusto.', 1985, 1985, 1985, 'Anos 80', 'CASCO HISTâ”œأ´RICO', 41.65549500, -0.88403400, '0101000020E610000082AAD1AB014AECBF84D89942E7D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/53259501638.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/53259501638.webp', 'https://www.flickr.com/photos/zaragozaantigua/53259501638/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22975, 'Gabino Diego y Javier Gurruchaga 1994', 'Foto GEA. Noviembre de 1994. El escritor Luis Alegre presenta su primer libro, "Besos robados" en la Sala Oasis, aâ”œâ•‘n Cabaret, poco antes del desmantelamiento de las butacas. Javier Gurruchaga, en la ciudad porque representaba "Golfus de Roma" en el teatro Principal, realizâ”œâ”‚ un energâ”œآ®tico concierto para el evento. En la foto, acompaâ”œâ–’ado de Gabino Diego, compaâ”œâ–’ero del cantante en la citada comedia musical.', 1994, 1994, 1994, 'Anos 90', 'CASCO HISTâ”œأ´RICO', 41.65507100, -0.88560200, '0101000020E6100000CCB56801DA56ECBF6DC7D45DD9D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15105613266.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15105613266.webp', 'https://www.flickr.com/photos/zaragozaantigua/15105613266/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23039, 'Av. de Câ”œآ®sar Augusto 1991', 'Imagen capturada desde la altura del inmueble del nâ”¬â•‘ 1 de la calle del Conde de Aranda y centrada en el remodelado tramo de la avenida de Câ”œآ®sar Augusto donde destacan la entrada y salida del nuevo aparcamiento subterrâ”œأ­neo con capacidad para 349 vehâ”œآ،culos. En la funcionalidad moderna del resultado destaca la recuperaciâ”œâ”‚n del empedrado y las farolas "de corte antiguo". El importe total de esta intervenciâ”œâ”‚n, unos 402 millones de pesetas, fue cubierto por la empresa Estacionamientos El Pilar, S.A. (EPSA), concesionaria de la explotaciâ”œâ”‚n comercial del aparcamiento, cuyas instalaciones pasarâ”œأ­n a propiedad municipal en el aâ”œâ–’o 2041.', 1991, 1991, 1991, 'Anos 90', 'CASCO HISTâ”œأ´RICO', 41.65465300, -0.88429200, '0101000020E61000006DA983BC1E4CECBF399D64ABCBD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50378130418.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50378130418.webp', 'https://www.flickr.com/photos/zaragozaantigua/50378130418/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23049, 'Calle de las Armas 1994', 'Aspecto del primer tramo de la calle de las Armas con el telâ”œâ”‚n de fondo del Mercado Central Lanuza y la avenida de Câ”œآ®sar Augusto. En primer tâ”œآ®rmino y a la izquierda, vecinos de la zona sentados junto al decimonâ”œâ”‚nico inmueble del nâ”¬â•‘ 22-26, proyectado por Ricardo Magdalena, donde se ubicaran las antiguas "escuelas de la Golondrina", por el nombre de la calle luego redenominada de Mosâ”œآ®n Pedro Dosset, y que actualmente acoge al Centro Pâ”œâ•‘blico de Educaciâ”œâ”‚n de Personas Adultas (CPEPA) Gâ”œâ”‚mez Lafuente. Hacia el fondo, flanquean el contenedor de basura los solares de los antiguos nâ”¬â•‘ 8, 10 y 12 a la izquierda, y a la derecha de los derribados nâ”¬â•‘ 5, 7 y 11, algunos luego reedificados.', 1994, 1994, 1994, 'Anos 90', 'CASCO HISTâ”œأ´RICO', 41.65647300, -0.88400200, '0101000020E6100000AA27F38FBE49ECBF7FDAA84E07D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50440860042.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50440860042.webp', 'https://www.flickr.com/photos/zaragozaantigua/50440860042/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23073, 'Barrio de San Pablo 2004', 'Reciente vista en altura de la antigua "Poblaciâ”œâ”‚n del Rey", vertebrada sobre los ejes perpendiculares que partâ”œآ،an de la plaza del Mercado (Las Armas, San Blas -a la izquierda de la torre-, San Pablo, Boggiero), con la referencia central de la gâ”œâ”‚tica iglesia de San Pablo.', 2004, 2004, 2004, 'Siglo XXI', 'CASCO HISTâ”œأ´RICO', 41.65613400, -0.88619500, '0101000020E6100000791EDC9DB55BECBF97E5EB32FCD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15257002696.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15257002696.webp', 'https://www.flickr.com/photos/zaragozaantigua/15257002696/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
