INSERT INTO public.photos VALUES (23093, 'SEPU Torre Nueva ca. 2000', 'Vista del edificio de los almacenes SEPU (Sociedad Espaâ”œâ–’ola de Precios â”œأœnicos) en la calle Torre Nueva de Zaragoza, esquina con la de Antâ”œâ”‚n Trillo, segâ”œâ•‘n proyecto de Miguel â”œأ¼ngel Navarro de 1935. Se levanta en el solar de la antigua casa palacio de los condes de Bureta. Durante siete dâ”œآ®cadas albergâ”œâ”‚ esos grandes almacenes, desaparecidos en 2002. Hoy estâ”œأ­ ocupado por viviendas y en sus bajos hay un supermercado. En el patio interior se conservan las escaleras mecâ”œأ­nicas de madera, las primeras que se instalaron en Zaragoza. Fuente: AMZ.', 2000, 2000, 2000, 'Siglo XXI', 'CASCO HISTâ”œأ´RICO', 41.65533100, -0.88303200, '0101000020E610000080492A53CC41ECBF0987DEE2E1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21243415066.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21243415066.webp', 'https://www.flickr.com/photos/zaragozaantigua/21243415066/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23760, 'Pasarela del Bicentenario 2008', 'La pasarela del Bicentenario cruza el râ”œآ،o Ebro entre La Cartuja Baja y La Alfranca, en el tâ”œآ®rmino de Pastriz. Forma parte del Camino Natural de los Sotos y Galachos del Ebro, que conecta el final del paseo de Echegaray y Caballero con La Alfranca, sede del Centro Internacional del Agua y el Medio Ambiente. Fue diseâ”œâ–’ada por Luis Javier Sanz. En la foto, â”œâ•‘ltima fase de su construcciâ”œâ”‚n, con las barandillas laterales sin colocar, el 17 de marzo de 2008. Serâ”œأ­ inaugurada ese mismo aâ”œâ–’o, el 6 de junio, junto con el Camino Natural de la Alfranca. Fuente: www.panoramio.com/photo/8625587', 2008, 2008, 2008, 'Siglo XXI', NULL, 41.61495600, -0.81578100, '0101000020E6100000755776C1E01AEABF4F3DD2E0B6CE4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21556325342.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21556325342.webp', 'https://www.flickr.com/photos/zaragozaantigua/21556325342/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23102, 'Calle Torrenueva 2009', 'Imagen del nuevo edificio habilitado en la referencial esquina entre las calles de Torrenueva y Antâ”œâ”‚n Trillo. Aquâ”œآ، estuvo la solera de la antigua casa palacio de los condes de Bureta, derribada para construir, segâ”œâ•‘n proyecto de Miguel â”œأ¼ngel Navarro en 1935, el edificio que albergâ”œâ”‚ por siete dâ”œآ®cadas los irrepetibles almacenes SEPU (Sociedad Espaâ”œâ–’ola de Precios â”œأœnicos). En 2002 se produjo su cierre comercial, quedando en barbecho hasta la intervenciâ”œâ”‚n que, proyectada en 2004, y respetando la fachada (catalogada de Interâ”œآ®s Ambiental), lo ha reconvertido en viviendas particulares y bajos comerciales. Sigue siendo uno de los abrumadores dominios de la nostalgia urbana, en su versiâ”œâ”‚n mâ”œأ­s desatada. Fuente: Joaquâ”œآ،n Sicilia y Asociados, arquitectura.', 2009, 2009, 2009, 'Siglo XXI', 'CASCO HISTâ”œأ´RICO', 41.65533100, -0.88303200, '0101000020E610000080492A53CC41ECBF0987DEE2E1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24194860103.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24194860103.webp', 'https://www.flickr.com/photos/zaragozaantigua/24194860103/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23460, 'Casa de la Condesa de Bureta 1935', 'Puerta de la casa de la Condesa de Bureta (Marâ”œآ،a de la Consolaciâ”œâ”‚n Domitila Azlor y Villavicencio (1773-1814), considerada heroâ”œآ،na de los asedios de Zaragoza (1808-1809) en la calle de Torre Nueva. Sobre el solar se construyâ”œâ”‚ al poco tiempo el edificio de los almacenes SEPU (Sociedad Espaâ”œâ–’ola de Precio â”œأœnico). La imagen ilustra la noticia del inminente derribo de la casa. Fuente visual: foto Palacio, en Revista Blanco y Negro.', 1935, 1935, 1935, 'Anos 30', 'CASCO HISTâ”œأ´RICO', 41.65533100, -0.88303200, '0101000020E610000080492A53CC41ECBF0987DEE2E1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20548270379.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20548270379.webp', 'https://www.flickr.com/photos/zaragozaantigua/20548270379/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23924, '&quot;Parque de Artillerâ”œآ،a&quot; 1967', 'Archivo Municipal. Gerardo Sancho Ramo. 1967. La instalaciâ”œâ”‚n militar del Ejâ”œآ®rcito de Tierra denominada "Parque de Artillerâ”œآ،a" ocupaba 16440 m2 entre las calles de Agustina de Aragâ”œâ”‚n y de Ramâ”œâ”‚n Pignatelli, muy cerca de la plaza del Portillo, y del cuartel de Sangenis (o Pontoneros, de otros 15.681 m2 de extensiâ”œâ”‚n). Con la denominada "Operaciâ”œâ”‚n Cuarteles" (finales aâ”œâ–’os setenta), y a cambio de unos dineros, este cuartel pasâ”œâ”‚ a propiedad municipal. Asâ”œآ،, se pudo prolongar la calle de Mayoral, y se construyâ”œâ”‚ el Instituto de Educaciâ”œâ”‚n Secundaria "Ramâ”œâ”‚n y Cajal". En la imagen, turbamulta de caâ”œâ–’ones en desuso del "Parque". A la izquierda, tras los muros, la calle de Agustina de Aragâ”œâ”‚n.', 1967, 1967, 1967, 'Anos 60', 'CASCO HISTâ”œأ´RICO', 41.65492400, -0.89040200, '0101000020E61000003160C9552C7EECBFC9AEB48CD4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15467645709.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15467645709.webp', 'https://www.flickr.com/photos/zaragozaantigua/15467645709/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23939, 'Calle San Martâ”œآ،n c.1970', 'Pintura de Claudio Gâ”œâ”‚mez Villanueva publicada en 2014 en la revista de la Asociaciâ”œâ”‚n Empresarial de Fontanerâ”œآ،a de Zaragoza. Recrea trabajos de fontanerâ”œآ،a en la calle de San Martâ”œآ،n, esquina con la del General Franco (derecha). Al fondo se adivina la câ”œâ•‘pula de la iglesia de Santiago. Protagonizando la foto, la entrada del cine Victoria (1943-1985), con un reestreno de "Gilda" (Charles Vidor, 1946). Fuente: www.facebook.com/groups/fotosantiguasdezaragoza/permalink...', 1970, 1970, 1970, 'Anos 70', 'CASCO HISTâ”œأ´RICO', 41.65466800, -0.88632000, '0101000020E6100000944DB9C2BB5CECBF6EDE3829CCD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27584461584.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27584461584.webp', 'https://www.flickr.com/photos/zaragozaantigua/27584461584/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23952, 'San Antâ”œâ”‚n en San Pablo c.1969', 'Ayuntamiento de Zaragoza/Gerardo Sancho Ramo. Junto a la entrada a la Iglesia de San Pablo, el 17 de enero es el dâ”œآ،a de bendiciâ”œâ”‚n de animales irracionales, por obra y gracia del eremita San Antâ”œâ”‚n (251-356).', 1969, 1969, 1969, 'Anos 60', 'CASCO HISTâ”œأ´RICO', 41.65593600, -0.88619600, '0101000020E61000009012BBB6B75BECBF7022FAB5F5D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14740482207.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14740482207.webp', 'https://www.flickr.com/photos/zaragozaantigua/14740482207/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23986, 'Chicho Sâ”œأ­nchez Ferlosio 1986', 'Foto Roger Hernando. Josâ”œآ® Antonio Julio Onâ”œآ®simo Sâ”œأ­nchez Ferlosio devino en Chicho Sâ”œأ­nchez Ferlosio, se hizo trovador pensante, y se encontrâ”œâ”‚ en la otra acera del Râ”œآ®gimen. En el reino de los bardos, se relacionâ”œâ”‚ con poetas polifacâ”œآ®ticos, juglares con agujeros en los bolsillos, musas carnales, y gentes varias del poblado universo onâ”œآ،rico de las dâ”œآ®cadas de los 70 y 80 del pasado siglo. Falleciâ”œâ”‚ en 2003, y dejâ”œâ”‚ una huella sonora perdurable. En la imagen, Chicho Sâ”œأ­nchez Ferlosio (a la derecha) sentado con Luis Felipe Alegre (otro que tal baila), en el Oasis. Fuente visual: elsilbovulnerado.blogspot.com.es/p/historial-grupo.html', 1986, 1986, 1986, 'Anos 80', 'CASCO HISTâ”œأ´RICO', 41.65522400, -0.88572900, '0101000020E610000014CD0358E457ECBFF3C64961DED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15515040047.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15515040047.webp', 'https://www.flickr.com/photos/zaragozaantigua/15515040047/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
