INSERT INTO public.photos VALUES (24393, 'Avenida Câ”œآ®sar Augusto 2011', 'Foto: Oliver Duch. Onâ”œآ،rica y pictâ”œâ”‚rica instantâ”œأ­nea, tomada el 15 de noviembre de 2011, durante las obras de ampliaciâ”œâ”‚n de la lâ”œآ،nea 1 del tranvâ”œآ،a. La avenida de Câ”œآ®sar Augusto resultâ”œâ”‚ parcialmente anegada por la lluvia. Al fondo y reflejada en el agua, iglesia de Santo Tomâ”œأ­s de Aquino o de los Escolapios. Fuente: Heraldo de Aragâ”œâ”‚n.', 2011, 2011, 2011, 'Siglo XXI', 'CASCO HISTâ”œأ´RICO', 41.65539500, -0.88385200, '0101000020E6100000572250FD8348ECBF207BBDFBE3D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26052396338.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26052396338.webp', 'https://www.flickr.com/photos/zaragozaantigua/26052396338/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
