INSERT INTO public.photos VALUES (24441, 'Pl. del Mercado 1869', '"Saragossa, the Market". Al fondo, las calles Cerdâ”œأ­n y Escuelas Pâ”œآ،as. Al fondo de la calle Cerdâ”œأ­n, la câ”œâ•‘pula de la Iglesia de Santiago el Mayor. Fuente visual: Robert Peters Napper-Francis Frith & Co., en Victoria and Albert Museum, London, 1860-1870.', 1869, 1869, 1869, 'Siglo XIX', 'CASCO HISTâ”œأ´RICO', 41.65600800, -0.88323500, '0101000020E610000088D7F50B7643ECBF0AF5F411F8D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14909212321.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14909212321.webp', 'https://www.flickr.com/photos/zaragozaantigua/14909212321/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
