INSERT INTO public.photos VALUES (24446, 'Mercado Central 1970', 'El pavo es azteca, omnâ”œآ،voro, proteico, y escandaloso. Encaja bien en esta ciudad. En la imagen, un pequeâ”œâ–’o rebaâ”œâ–’o de pavos es paseado para publicitar su venta por un orondo pavero, en el lado de los pares de la plaza de Lanuza. A la derecha y al fondo, esquina sur del Mercado Central con la calle de la Torre Nueva. Detrâ”œأ­s de la pavada, un grupo de personas contempla esta tradicional escena invernal, asociada a la importada celebraciâ”œâ”‚n azteca del solsticio de invierno, que pronto pasarâ”œآ،a de pintoresca a desaparecida en nuestros pagos.', 1970, 1970, 1970, 'Anos 70', 'CASCO HISTâ”œأ´RICO', 41.65562300, -0.88306900, '0101000020E6100000C99063EB1942ECBFB1C05774EBD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15117496621.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15117496621.webp', 'https://www.flickr.com/photos/zaragozaantigua/15117496621/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24545, 'Nuevo Mercado 1895', '"Proyecto del Nuevo Mercado. Fachada frente a la calle de Cerdâ”œأ­n; planta". Fâ”œآ®lix Navarro Pâ”œآ®rez, arquitecto, 1895. Tinta y acuarela sobre tela, 125 x 138 cm. Excelente ilustraciâ”œâ”‚n del alzado sur del Nuevo Mercado de Zaragoza, que serâ”œأ­ inaugurado en 1903 y luego denominado Mercado Central o de Lanuza.', 1895, 1895, 1895, 'Siglo XIX', 'CASCO HISTâ”œأ´RICO', 41.65567300, -0.88336100, '0101000020E6100000B9FAB1497E44ECBF63EFC517EDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54323517061.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54323517061.webp', 'https://www.flickr.com/photos/zaragozaantigua/54323517061/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24906, 'Necrâ”œâ”‚polis paleocristiana siglo V', 'Necrâ”œâ”‚polis paleocristiana bajo la calzada de la actual calle de Mosâ”œآ®n Pedro Dosset, junto a la de Las Armas. â”œأ«poca romana (s. V). Durante las obras de pavimentaciâ”œâ”‚n y renovaciâ”œâ”‚n de servicios de la zona en 2002, se encontrâ”œâ”‚ en la antigua calle de la Golondrina un conjunto de inhumaciones en fosa, con cubierta de tejas planas y ataâ”œâ•‘d de madera. Alguna presenta revestimiento de mosaico, hallazgo â”œâ•‘nico en la historia de la ciudad. Estos restos se encontraron cerca de la necrâ”œâ”‚polis occidental de Caesaraugusta (calle Predicadores 20-30, siglos III al XIII), si bien no forman parte de ese conjunto. Fuente: Revista Saldvie. Universidad de Zaragoza, 2002.', 450, 400, 499, 'Siglo XIX', 'CASCO HISTâ”œأ´RICO', 41.65660800, -0.88408900, '0101000020E6100000651BB803754AECBF5F251FBB0BD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18552193299.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18552193299.webp', 'https://www.flickr.com/photos/zaragozaantigua/18552193299/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25097, 'Muerte de Lanuza 1591', 'أ”أ‡آ£Represiâ”œâ”‚n de las tropas castellanas: muerte de don Juan de Lanuza (1564-1591) por defender a Antonio Pâ”œآ®rezأ”أ‡أک. Grabado del siglo XIX coloreado posteriormente. El Justicia de Aragâ”œâ”‚n permanece a la derecha, mientras preparan su decapitaciâ”œâ”‚n en la plaza del Mercado. Al fondo, anacrâ”œâ”‚nicas câ”œâ•‘pulas de San Ildefonso (centro) y Santo Tomâ”œأ­s de Villanueva (izquierda). Fuente visual: www.superstock.com', 1591, 1591, 1591, 'Siglo XIX', 'CASCO HISTâ”œأ´RICO', 41.65584600, -0.88318800, '0101000020E61000005B07077B1343ECBF309B00C3F2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/40205982815.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/40205982815.webp', 'https://www.flickr.com/photos/zaragozaantigua/40205982815/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25134, 'San Pablo 1891', 'Dibujo de la plaza, iglesia y torre de San Pablo, en 1891.', 1891, 1891, 1891, 'Siglo XIX', 'CASCO HISTâ”œأ´RICO', 41.65613400, -0.88619500, '0101000020E6100000791EDC9DB55BECBF97E5EB32FCD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18945535232.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18945535232.webp', 'https://www.flickr.com/photos/zaragozaantigua/18945535232/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25180, 'Iglesia de San Pablo 1943', 'Fotografâ”œآ،a en blanco y negro del colorista lienzo "Vista urbana con iglesia y gente", firmado en 1943 por el paisajista barcelonâ”œآ®s Ramâ”œâ”‚n Lâ”œâ”‚pez Muâ”œâ–’oz. Posiblemente la imagen se ha capturado durante la exposiciâ”œâ”‚n de esta obra en la filial zaragozana de la Sala Gaspar de Barcelona, que desde 1942 estaba abierta en los bajos del inmueble del antiguo nâ”¬â•‘ 3 de la calle de la Yedra, esquinero con la plaza de la Leâ”œâ–’a. Este espacio expositivo estuvo activo hasta su cierre en 1950. La pintura ilustra una vista desde cierta altura de la dieciochesca fachada de la iglesia parroquial de San Pablo Apâ”œâ”‚stol, recayente a la homâ”œâ”‚nima calle, posiblemente durante la salida de un oficio dominical. Al fondo y a la izquierda, la plaza de San Pablo.', 1943, 1943, 1943, 'Anos 40', 'CASCO HISTâ”œأ´RICO', 41.65600800, -0.88620100, '0101000020E610000002D71533C25BECBF0AF5F411F8D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/48594159637.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/48594159637.webp', 'https://www.flickr.com/photos/zaragozaantigua/48594159637/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25191, 'Plano del mercado y pellerich ca. 1460', 'La Plaza del Mercado era el mâ”œأ­s importante espacio social de actos y celebraciones mercantiles y festivas de la ciudad, y tambiâ”œآ®n el escenario de la imparticiâ”œâ”‚n de justicia, bien por los tribunales civiles, bien por el eclesiâ”œأ­stico de la Inquisiciâ”œâ”‚n. Ese lugar concreto se denominaba "plaza de la Justicia", donde estaba instalada la "Picota", o "Pellerich" (denominaciâ”œâ”‚n que aparece en las "Ordinaciones" reales otorgadas a la ciudad de Zaragoza, que desde el s.XIII regulaban la organizaciâ”œâ”‚n municipal de la ciudad, incluyendo la Justicia). En este cadalso se ejecutaron pâ”œâ•‘blicamente las condenas a muerte, mediante la horca, o la decapitaciâ”œâ”‚n, como fue el caso del Justicia Juan de Lanuza a finales del s.XVI. Esto se hacâ”œآ،a al objeto de servir de ejemplo al pâ”œâ•‘blico sobre los efectos de transgredir las normas sociales. El plano representa el lugar donde estaba localizado el cadalso, o "pellerich", en el espacio de la plaza del Mercado donde confluâ”œآ،a el Trenque de la calle Nueva (calle Torrenueva), la calle de San Blas, la de San Pablo, la de la Cedacerâ”œآ،a (luego Escuelas Pâ”œآ،as), y la de la Albarderâ”œآ،a (luego Cerdâ”œأ­n). Fuente: Mâ”¬آ¬ Isabel Falcâ”œâ”‚n Pâ”œآ®rez, "Zaragoza en el siglo XV: morfologâ”œآ،a urbana, huertas y tâ”œآ®rmino municipal", IFC, 2011.', 1460, 1460, 1460, 'Siglo XIX', 'CASCO HISTâ”œأ´RICO', 41.65577500, -0.88325100, '0101000020E6100000F418E5999743ECBF6744696FF0D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15791168710.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15791168710.webp', 'https://www.flickr.com/photos/zaragozaantigua/15791168710/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25379, 'Calle de las Escuelas Pâ”œآ،as c.1976', 'En 1977 se derribâ”œâ”‚ la manzana que formaban las calles Cerdâ”œأ­n y Escuelas Pâ”œآ،as, en el tramo de la actual avenida de Câ”œآ®sar Augusto que llega del Coso al Mercado Central. Al fondo, la iglesia de las Escuelas Pâ”œآ،as.', 1976, 1976, 1976, 'Anos 70', 'CASCO HISTâ”œأ´RICO', 41.65487100, -0.88427000, '0101000020E610000079AF5A99F04BECBFA60C1CD0D2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14715464178.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14715464178.webp', 'https://www.flickr.com/photos/zaragozaantigua/14715464178/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
