INSERT INTO public.photos VALUES (25381, 'Mercado Central 1966', 'Archivo Municipal. Gerardo Sancho Ramo. Febrero 1966. Entrada al Mercado Central desde la Avenida Câ”œآ®sar Augusto-calle Torre Nueva.', 1966, 1966, 1966, 'Anos 60', 'CASCO HISTâ”œأ´RICO', 41.65560200, -0.88333000, '0101000020E6100000F86BB2463D44ECBF9A982EC4EAD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15097137153.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15097137153.webp', 'https://www.flickr.com/photos/zaragozaantigua/15097137153/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25382, 'Pl. de Lanuza 1966', 'Archivo Municipal de Zaragoza. Gerardo Sancho Ramo. 02/07/1966. "Plaza de Lanuza." En la imagen, fachada a la plaza de la manzana entre las calles Cerdâ”œأ­n y Escuelas Pâ”œآ،as.', 1966, 1966, 1966, 'Anos 60', 'CASCO HISTâ”œأ´RICO', 41.65562300, -0.88343900, '0101000020E6100000A759A0DD2145ECBFB1C05774EBD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15163516407.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15163516407.webp', 'https://www.flickr.com/photos/zaragozaantigua/15163516407/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
