INSERT INTO public.photos VALUES (25388, '4 Alcaldes 4, 1963', 'Camino de los "25 aâ”œâ–’os de Paz" (sic), imagen de 4 de los 5 â”œâ•‘ltimos alcaldes de la ciudad y del "Movimiento" (sic), capturada en 1963 durante la inauguraciâ”œâ”‚n de la sucursal del Mercado Central de la Caja de Ahorros de Zaragoza y etc. De izquierda a derecha: Josâ”œآ® Marâ”œآ،a Garcâ”œآ،a-Belenguer Garcâ”œآ،a (alcalde entre 1949-1954), Luis Gâ”œâ”‚mez Laguna (desde 1954), Juan Josâ”œآ® Rivas Bosch (entre 1939-1941), y Josâ”œآ® Marâ”œآ،a Sâ”œأ­nchez Ventura (entre 1946-1949). Faltaba Francisco Caballero Ibâ”œأ­â”œâ–’ez (entre 1941-1946), fallecido en 1954. Por arriba despunta el retrato del Generalâ”œآ،simo (sic). Fuente: "El municipio en Aragâ”œâ”‚n", DPZ, 2004', 1963, 1963, 1963, 'Anos 60', 'CASCO HISTâ”œأ´RICO', 41.65600800, -0.88323500, '0101000020E610000088D7F50B7643ECBF0AF5F411F8D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16420195809.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16420195809.webp', 'https://www.flickr.com/photos/zaragozaantigua/16420195809/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25389, 'Calle del Mercado 1877', '"Desde el Palacio de la Audiencia y sus gigantones del Coso, y por la calle Albarderâ”œآ،a, llamada hace poco Cerdâ”œأ­n, llego al Mercado, una ancha calle que llaman plaza, y que se queda pequeâ”œâ–’a cuando los lugareâ”œâ–’os la convierten en el zoco. Aquâ”œآ، cerca queda el Azoque que conduce a la vieja Morerâ”œآ،a, porque en Zaragoza todo estâ”œأ­ conectado, aunque no lo parezca. Subo a una casa de alquiler desde la que tengo buena vista, e instalo la câ”œأ­mara. Compruebo la luz, y hago varias capturas, segâ”œâ•‘n el sol. Hay justo abajo una fuente puesta por el Ayuntamiento, que me dicen que es muy reciente, aunque el agua no sale muy buena. Justo ahâ”œآ، estaba la picota donde ajusticiaban a malhechores, y cortaron la cabeza al que llamaban Justicia. Esta fue plaza tambiâ”œآ®n de toreros antes que la plaza del Campo del Toro, de justas y gestas de caballeros, de fuegos y hogueras, de capelardentes... Los contrastes de luz son brutales: de la oscuridad se pasa al deslumbre en un instante... â”¬أ­cuidado! Con los toldos desplegados, la plaza parece encogerse, aunque no deja de entrar gente en ella. El bullicio es indescriptible. Si esta gente habla asâ”œآ، del natural, câ”œâ”‚mo serâ”œأ­ cuando se echen a gritar... A la izquierda estâ”œأ­ la calle de San Blas. A la derecha, la de la Torre Nueva. Al fondo, la de Antonio Pâ”œآ®rez, que termina en la puerta de San Ildefonso y que conserva un torreâ”œâ”‚n de la Sudda musulmana. Ahora que el sol ya no cae como a plomo, nos vamos a comer a una antigua posada, en la calle de San Pablo." Del apâ”œâ”‚crifo "Diario de un Gabacho en Zaragoza" (Jean Laurent, 1878) Fuente visual: Fototeca del Patrimonio Histâ”œâ”‚rico (www.mcu.es) Archivo Ruiz Vernacci. Jean Laurent y Câ”œآ،a. Original composiciâ”œâ”‚n realizada a partir del positivado estereoscâ”œâ”‚pico, por cortesâ”œآ،a del taller de GAZA.', 1877, 1877, 1877, 'Siglo XIX', 'CASCO HISTâ”œأ´RICO', 41.65562300, -0.88343900, '0101000020E6100000A759A0DD2145ECBFB1C05774EBD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/17715945103.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/17715945103.webp', 'https://www.flickr.com/photos/zaragozaantigua/17715945103/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25393, 'Plaza del Mercado 1591', 'Ilustraciâ”œâ”‚n del artâ”œآ،culo "El suplicio de Lanuza", en la secciâ”œâ”‚n "Momentos Histâ”œâ”‚ricos", de la revista "La Esfera" (1923), en que se recrean de aquellas formas los acontecimientos de Zaragoza de diciembre de 1591, que culminaron con la ejecuciâ”œâ”‚n del Justiciazgo Juan de Lanuza, separando la cabeza de su tronco. El dibujo estâ”œأ­ localizado en la "plaza del Ahorcado", en realidad plaza del Mercado, donde estaba ubicada desde antiguo la "picota" o sitial de las ejecuciones pâ”œâ•‘blicas. La dramâ”œأ­tica altura de la picota de esta reproducciâ”œâ”‚n, produce vâ”œآ®rtigo. A la derecha, interpretaciâ”œâ”‚n de la puerta de Toledo, del torreâ”œâ”‚n de la Zuda, y de la puerta de la Triperâ”œآ،a. Fuente visual: dibujo de Ricardo Marâ”œآ،n Llovet, revista "La Esfera" (Madrid)', 1591, 1591, 1591, 'Siglo XIX', 'CASCO HISTâ”œأ´RICO', 41.65580100, -0.88323900, '0101000020E6100000E3A7716F7E43ECBF90D78349F1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22591062637.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22591062637.webp', 'https://www.flickr.com/photos/zaragozaantigua/22591062637/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25395, 'Calle Escuelas Pâ”œآ،as 1968', 'Calle de las Escuelas Pâ”œآ،as. Al fondo, la iglesia de los Escolapios. Fuente visual: Foto Leonardo Pâ”œآ®rez Obis, donada por â”œأ¼ngel Hernâ”œأ­ndez Mostajo para www.rafaelcastillejo.com', 1968, 1968, 1968, 'Anos 60', 'CASCO HISTâ”œأ´RICO', 41.65536500, -0.88406700, '0101000020E610000071218FE0464AECBFB6F81400E3D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22849889700.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22849889700.webp', 'https://www.flickr.com/photos/zaragozaantigua/22849889700/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25396, 'Pl. de Lanuza 1967', 'Plaza de Lanuza, junto al Mercado Central, en la esquina de El Pequeâ”œâ–’o Catalâ”œأ­n. A la derecha, la calle de San Blas. Fuente visual: Foto Leonardo Pâ”œآ®rez Obis, donada por â”œأ¼ngel Hernâ”œأ­ndez Mostajo para www.rafaelcastillejo.com', 1967, 1967, 1967, 'Anos 60', 'CASCO HISTâ”œأ´RICO', 41.65590200, -0.88355200, '0101000020E6100000B1170AD80E46ECBFC4B0C398F4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23181740161.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23181740161.webp', 'https://www.flickr.com/photos/zaragozaantigua/23181740161/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25400, 'Tâ”œâ•‘mulo Baltasar Carlos 1646', 'En 1646, el rey Felipe IV y su hijo el prâ”œآ،ncipe Baltasar Carlos viajaron a Zaragoza, donde el chaval, de 16 aâ”œâ–’os, contrajo la viruela y muriâ”œâ”‚, el 9 de octubre. Su cadâ”œأ­ver permaneciâ”œâ”‚ en la ciudad hasta el 16, cuando fue trasladado a Monasterio de San Lorenzo de El Escorial. Posteriormente se le hicieron dos capillas ardientes; una en la Seo y otra en la plaza del Mercado, donde se acostumbraban a celebrar las exequias reales. Para esta â”œâ•‘ltima, la Junta eligiâ”œâ”‚ la traza de Miguel Ramâ”œâ”‚n. Se hicieron solemnes vâ”œآ،speras y responsos durante los dâ”œآ،as de la vigilia y de las exequias, 20 y 21 de octubre. En el grabado, de Josephus Vallâ”œآ®s, se representa el tâ”œâ•‘mulo honorâ”œآ،fico de la plaza del Mercado, que medâ”œآ،a 154 palmos de altura. Este dibujo estâ”œأ­ incluido en la publicaciâ”œâ”‚n "Obelisco histâ”œâ”‚rico y honorario que la imperial ciudad de Zaragoza erigiâ”œâ”‚ a la inmortal memoria del serenâ”œآ،simo seâ”œâ–’or don Balsar Carlos de Austria, prâ”œآ،ncipe de las Espaâ”œâ–’as", escrito por Juan Francisco Andrâ”œآ®s, cronista del reino de Aragâ”œâ”‚n, en Zaragoza, 1646. Fuente visual: Biblioteca Nacional de Austria.', 1646, 1646, 1646, 'Siglo XIX', 'CASCO HISTâ”œأ´RICO', 41.65584600, -0.88318800, '0101000020E61000005B07077B1343ECBF309B00C3F2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30842811992.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30842811992.webp', 'https://www.flickr.com/photos/zaragozaantigua/30842811992/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25403, 'Ocupaciâ”œâ”‚n castellana 1591', 'أ”أ‡آ£Nuevos suplicios en Zaragoza durante la ocupaciâ”œâ”‚n por tropas castellanasأ”أ‡أک. Grabado del siglo XIX coloreado posteriormente. Tras las alteraciones de Zaragoza del verano de 1591, el ejâ”œآ®rcito de Castilla tomâ”œâ”‚ Zaragoza, en noviembre. Varias personas fueron ejecutadas, previamente a la decapitaciâ”œâ”‚n del Justicia Juan de Lanuza. Fuente visual: www.magnoliabox.com', 1591, 1591, 1591, 'Siglo XIX', 'CASCO HISTâ”œأ´RICO', 41.65584600, -0.88318800, '0101000020E61000005B07077B1343ECBF309B00C3F2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/40390624734.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/40390624734.webp', 'https://www.flickr.com/photos/zaragozaantigua/40390624734/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25816, 'Vista de Zaragoza c.1866', 'A.M.Z. Sign. 0854. Vista de Zaragoza. [1880]. Realizada circa 1866. Dibujo de Francisco Pradilla. Se observa la torre de la iglesia de San Pablo y las iglesias de San Juan de los Panetes y Santa Isabel. En el texto explicativo del Ayuntamiento de Zaragoza se asegura que en la imagen la disposiciâ”œâ”‚n original estâ”œأ­ invertida. Nosotros aâ”œâ–’adimos que segâ”œâ•‘n se mire. Fechada mediante los datos aportados en www.facebook.com/photo.php?fbid=376521369171365&set=g...', 1866, 1866, 1866, 'Siglo XIX', 'CASCO HISTâ”œأ´RICO', 41.65584300, -0.88874200, '0101000020E6100000BB9C12109370ECBFBF27D6A9F2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14858571632.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14858571632.webp', 'https://www.flickr.com/photos/zaragozaantigua/14858571632/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25819, 'Calle Miguel de Ara 1951', 'Archivo Municipal de Zaragoza. Archivo Mora. Junio 1951. "Calle de Ara, (Miguel)." Esta es una larga y estrecha calle que une la calle de San Pablo con la de Pignatelli. En la imagen, tramo de la calle Miguel de Ara desde la calle General Franco, hasta la de Basilio Boggiero, al fondo.', 1951, 1951, 1951, 'Anos 50', 'CASCO HISTâ”œأ´RICO', 41.65464700, -0.88620500, '0101000020E61000005DA79196CA5BECBF56B60F79CBD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14886572007.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14886572007.webp', 'https://www.flickr.com/photos/zaragozaantigua/14886572007/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
