INSERT INTO public.photos VALUES (25823, 'Calle del Saco 1951', 'Archivo Municipal de Zaragoza. Archivo Mora. Junio 1951. "Calle del Saco." Menos que calle, tratâ”œأ­base de un callejâ”œâ”‚n de la calle Echeandâ”œآ،a, a poco de empezarla desde la calle Boggiero.', 1951, 1951, 1951, 'Anos 50', 'CASCO HISTâ”œأ´RICO', 41.65539000, -0.88531100, '0101000020E6100000F23FF9BB7754ECBF0E10CCD1E3D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14897956267.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14897956267.webp', 'https://www.flickr.com/photos/zaragozaantigua/14897956267/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
