INSERT INTO public.photos VALUES (25825, 'Iglesia de San Pablo 1844', 'Dibujo de Jenaro Pâ”œآ®rez Villaamil, grabado por A. Guesjoâ”œâ•£, lith., por la casa A. Hauser, impreso por Lemercier, e incluido en la obra "Espaâ”œâ–’a artâ”œآ،stica y monumental vistas y descripciâ”œâ”‚n de los sitios y monumentos mâ”œأ­s notables de Espaâ”œâ–’a", Parâ”œآ،s.', 1844, 1844, 1844, 'Siglo XIX', 'CASCO HISTâ”œأ´RICO', 41.65606400, -0.88593500, '0101000020E610000061376C5B9459ECBF9E0AB8E7F9D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14957554115.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14957554115.webp', 'https://www.flickr.com/photos/zaragozaantigua/14957554115/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25829, 'Iglesia de San Pablo 1865', 'Portada Norte de la iglesia de San Pablo hacia 1865. Portada gâ”œâ”‚tica del siglo XV esculpida en alabastro, que da a la calle de San Blas. Llamada Puerta de la Tramontana o Puerta del Santo Cristo. En 1594 se le aâ”œâ–’ade el alero de madera. Fuente: Colecciâ”œâ”‚n Antonio Arguas.', 1865, 1865, 1865, 'Siglo XIX', 'CASCO HISTâ”œأ´RICO', 41.65630000, -0.88583600, '0101000020E610000095D233BDC458ECBFB22E6EA301D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15169430412.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15169430412.webp', 'https://www.flickr.com/photos/zaragozaantigua/15169430412/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25831, 'San Pablo 1877', 'Imagen en relativa altura de la poderosa torre de la parroquia de San Pablo, tomada desde el oeste, lo que permite ver la antigua puerta abierta a los pies de la iglesia en 1587, llamada del Fosal porque allâ”œآ، estaba el cementerio parroquial, y luego de los Ajusticiados, en la angulosa plaza de San Pablo. A la izquierda, al fondo, el Torreâ”œâ”‚n de la Zuda, y la original e inacabada â”œâ•‘nica torre del Pilar. A la derecha, la Torre Nueva. A su lado, la torre de San Felipe. Fuente visual: Fototeca del Patrimonio Histâ”œâ”‚rico, Archivo Ruiz Vernacci. Foto Jean Laurent.', 1877, 1877, 1877, 'Siglo XIX', 'CASCO HISTâ”œأ´RICO', 41.65613400, -0.88619500, '0101000020E6100000791EDC9DB55BECBF97E5EB32FCD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20168997966.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20168997966.webp', 'https://www.flickr.com/photos/zaragozaantigua/20168997966/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25833, 'Calle San Blas 1998', 'Excavaciâ”œâ”‚n arqueolâ”œâ”‚gica en el cruce de la calle San Blas con Aguadores (izquierda), con motivo de las obras de alineaciâ”œâ”‚n de la zona en octubre de 1998. Al fondo, la torre de San Pablo. Se hallaron restos de hornos de â”œآ®poca islâ”œأ­mica y una cisterna romana. Fuente: Colecciâ”œâ”‚n particular.', 1998, 1998, 1998, 'Anos 90', 'CASCO HISTâ”œأ´RICO', 41.65661600, -0.88717900, '0101000020E6100000E355D636C563ECBFE2033BFE0BD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22020688995.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22020688995.webp', 'https://www.flickr.com/photos/zaragozaantigua/22020688995/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25834, 'San Pablo c.1877', '"Iglesia de San Pablo. Puerta del Cristo". Imagen de la puerta norte, o "Tramontana", de la iglesia parroquial de San Pablo, que permitâ”œآ،a el acceso al templo desde la calle de San Blas. Esta puerta estâ”œأ­ datada en el siglo XV, cuando Antâ”œâ”‚n del Prado tallâ”œâ”‚ en madera el frontâ”œâ”‚n plateresco que la corona. Actualmente se halla tapiada, y despojada de los dos bancos laterales. Fuente visual: Jean Laurent y Câ”œآ،a, Archivo Ruiz Vernacci (Fototeca del Patrimonio Histâ”œâ”‚rico, www.mcu.es/)', 1877, 1877, 1877, 'Siglo XIX', 'CASCO HISTâ”œأ´RICO', 41.65632200, -0.88595300, '0101000020E6100000FA60191BBA59ECBF9AD2FA5B02D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22643885050.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22643885050.webp', 'https://www.flickr.com/photos/zaragozaantigua/22643885050/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25835, 'Plaza de San Pablo 1951', 'Imagen de la antigua plaza de San Pablo, como espacio delimitado por los pies de la iglesia parroquial de San Pablo (derecha), con el acceso a travâ”œآ®s de la puerta de los Ahorcados, o del Fosal; la calle de San Blas (al fondo); y la propia calle de San Pablo (en primer plano). Fuente visual: Archivo Mora, AMZ.', 1951, 1951, 1951, 'Anos 50', 'CASCO HISTâ”œأ´RICO', 41.65621000, -0.88656500, '0101000020E610000058E71890BD5EECBF72A774B0FED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22798168538.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22798168538.webp', 'https://www.flickr.com/photos/zaragozaantigua/22798168538/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25837, 'Calle de San Blas 1998', 'A finales de abril de 1997 el Ayuntamiento de Zaragoza aprobâ”œâ”‚, en Pleno Municipal Extraordinario, el primer Plan Integral del Casco Histâ”œâ”‚rico (PICH), que con un presupuesto de casi 21.000 millones de pesetas tenâ”œآ،a previsto impulsar 18 programas y mâ”œأ­s de 200 actuaciones hasta 2004, la mayor parte a travâ”œآ®s de la Sociedad Municipal de Rehabilitaciâ”œâ”‚n Urbana, al objeto de "romper la segregaciâ”œâ”‚n social y espacial" de esta zona de la ciudad, sobre todo en los barrios de San Pablo, y La Magdalena. La inicial gestiâ”œâ”‚n del PP puso acento destacado en los aspectos fâ”œآ،sicos de la rehabilitaciâ”œâ”‚n, dejando que el libre mercado se encargara de la mejora de los aspectos sociales y econâ”œâ”‚micos. Asâ”œآ، fue. En la imagen, la alcaldesa Luisa Fernanda Rudi y el concejal Josâ”œآ® Luis Santacruz, de inspecciâ”œâ”‚n por la calle de San Blas a la altura del inmueble del nâ”¬â•‘ 73, en el barrio de San Pablo.', 1998, 1998, 1998, 'Anos 90', 'CASCO HISTâ”œأ´RICO', 41.65665100, -0.88774500, '0101000020E61000002A00C6336868ECBF5EF1D4230DD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24505520322.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24505520322.webp', 'https://www.flickr.com/photos/zaragozaantigua/24505520322/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25838, 'San Pablo 1844', '"Iglesia de San Pablo en Zaragoza". Dibujo de Genaro Pâ”œآ®rez de Villaamil incluido en la obra "Espaâ”œâ–’a artâ”œآ،stica y monumental. Vistas y descripciâ”œâ”‚n de los sitios y monumentos mâ”œأ­s notables de Espaâ”œâ–’a". Fuente visual: www.flickr.com/photos/odisea2008/6309861440/', 1844, 1844, 1844, 'Siglo XIX', 'CASCO HISTâ”œأ´RICO', 41.65588600, -0.88609200, '0101000020E610000053E9279CDD5AECBFBFF38B12F4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24938529049.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24938529049.webp', 'https://www.flickr.com/photos/zaragozaantigua/24938529049/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25839, 'Calle Echeandâ”œآ،a 2005', 'Foto: Marina Ovejero. Solar vallado en la confluencia de la calle de Basilio Boggiero (desde donde estâ”œأ­ tomada la foto) con la de Pedro Echeandâ”œآ،a (al fondo), en septiembre de 2005. Durante 2006, esta zona, que incluye una plazuela en Boggiero frente al Oasis Club, fue objeto de algunos retoques estâ”œآ®ticos, culminados en 2010 con la urbanizaciâ”œâ”‚n de parte del entorno, bautizâ”œأ­ndola como plaza del Padre Pedro Dâ”œآ،ez, que no merman su condiciâ”œâ”‚n de lugar inhâ”œâ”‚spito y ruinoso. A la derecha, inicio de las obras de construcciâ”œâ”‚n de un bloque de viviendas esquinero entre Echeandâ”œآ،a y Boggiero. Fuente: Heraldo de Aragâ”œâ”‚n.', 2005, 2005, 2005, 'Siglo XXI', 'CASCO HISTâ”œأ´RICO', 41.65518700, -0.88522700, '0101000020E61000007C28D192C753ECBFD6E1E82ADDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30901813414.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30901813414.webp', 'https://www.flickr.com/photos/zaragozaantigua/30901813414/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25840, 'Calle de San Blas 1951', 'Imagen de la calle de San Blas capturada desde la replaceta que se formaba en el arranque de la calle del Sacramento (hacia la izquierda, fuera de plano), porque los nuevos edificios de los nâ”œâ•‘meros 36-38, y 34-32, de la calle de San Blas habâ”œآ،an sido construidos retranqueados respecto de la anchura original de la calle, que era la que se ve que continâ”œâ•‘a luego, primero hasta la antigua calle de la Golondrina (redenominada recientemente de mosâ”œآ®n Pedro Dosset), y luego hasta el desemboque en la plaza de Lanuza, donde el Mercado Central, al fondo. Mâ”œأ­s adelante, todos estos edificios referidos, desde el nâ”œâ•‘mero 30, hasta el comienzo de la calle, serâ”œأ­n derribados y realineados los nuevos a la anchura moderna. A la derecha, y en primerâ”œآ،simo plano, el muro junto a la puerta de San Blas de la iglesia parroquial de San Pablo. Fuente visual: Archivo Mora, AMZ.', 1951, 1951, 1951, 'Anos 50', 'CASCO HISTâ”œأ´RICO', 41.65629000, -0.88547100, '0101000020E610000029CE5147C755ECBF8E588B4F01D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30948308201.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30948308201.webp', 'https://www.flickr.com/photos/zaragozaantigua/30948308201/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25841, 'Calle San Blas 2006', 'Fotograma de la pelâ”œآ،cula documental "Gente con Gancho" (â”œأ¼urea Martâ”œآ،nez, 2006), que retrata el barrio de San Pablo de Zaragoza. En la imagen, solar del nâ”œâ•‘mero 61 de la calle de San Blas, esquinero con la de Mariano Cerezo (al fondo a la izquierda). En 2007 se levantarâ”œأ­ allâ”œآ، el edificio Râ”œآ،o Bidasoa. Fuente: www.permanencias.eu/. Un extracto del documental se puede ver en vimeo.com/35249591.', 2006, 2006, 2006, 'Siglo XXI', 'CASCO HISTâ”œأ´RICO', 41.65659800, -0.88711500, '0101000020E6100000335019FF3E63ECBF3C4F3C670BD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31411211084.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31411211084.webp', 'https://www.flickr.com/photos/zaragozaantigua/31411211084/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25843, 'Calle de Mayoral 2005', 'Foto: Josâ”œآ® Marâ”œآ،a Ballestâ”œآ،n Miguel. Imagen de la calle de Mayoral, centrada en el desaparecido tramo de los antiguos edificios nâ”¬â•‘ 22 (derecha), 24 (centro), y 26 (izquierda), entre las calles de Boggiero y San Pablo. Conformaban una muestra de esa extraâ”œâ–’a categorâ”œآ،a edilicia que los expertos suelen denominar "arquitectura popular", aunque sin los atributos estâ”œآ®ticos suficientes , y que suele traducirse como "contingente, prescindible", a efectos prâ”œأ­cticos, como es el caso. Luego fueron derribados, y en su lugar hay un solar de esos que no lo son.', 2005, 2005, 2005, 'Siglo XXI', 'CASCO HISTâ”œأ´RICO', 41.65621000, -0.88903300, '0101000020E610000094128255F572ECBF72A774B0FED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31835738354.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31835738354.webp', 'https://www.flickr.com/photos/zaragozaantigua/31835738354/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25845, 'Echeandâ”œآ،a 1951', 'Imagen de la calle de Gregorio Echeandâ”œآ،a capturada desde el recoleto espacio, o callejâ”œâ”‚n, conformado entre los nâ”œâ•‘meros 14 (izquierda) y 18 (derecha) de esa calle, como â”œâ•‘nica forma de acceder al nâ”¬â•‘ 16. El mâ”œآ،nimo tamaâ”œâ–’o de este callejâ”œâ”‚n explicarâ”œآ،a que no tuviera denominaciâ”œâ”‚n propia. La numeraciâ”œâ”‚n de la calle Echeandâ”œآ،a avanza hacia la derecha, para desembocar en la calle de San Pablo. Hacia la izquierda, se llega a Boggiero. Fuente visual: foto Juan Mora Insa, en AMZ.', 1951, 1951, 1951, 'Anos 50', 'CASCO HISTâ”œأ´RICO', 41.65526400, -0.88483800, '0101000020E6100000EE4108C89750ECBF821FD5B0DFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33233850661.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33233850661.webp', 'https://www.flickr.com/photos/zaragozaantigua/33233850661/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25846, 'Calle Boggiero 1890', 'Imagen de un interesante mirador abierto en el antiguo nâ”¬â•‘ 35 de la calle Boggiero, en el tramo entre la calle de Mariano Cerezo y la de Miguel de Ara. Tiempo despuâ”œآ®s, la casona fue reconfigurada segâ”œâ•‘n criterios estâ”œآ®ticos menos mestizos y mâ”œأ­s regionalistas, y este bizarro ajimez fue hecho desaparecer. Fuente visual: fototipia de Joarizti y Mariezcurrena, en أ”أ‡آ£Zaragoza Artâ”œآ،stica, Monumental e Histâ”œâ”‚ricaأ”أ‡أک, Anselmo y Pedro Gascâ”œâ”‚n de Gotor (1890-91).', 1890, 1890, 1890, 'Siglo XIX', 'CASCO HISTâ”œأ´RICO', 41.65530400, -0.88637200, '0101000020E610000033E202D0285DECBF10786000E1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33784782044.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33784782044.webp', 'https://www.flickr.com/photos/zaragozaantigua/33784782044/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25848, 'Calle de Echeandâ”œآ،a c.1995', 'Imagen capturada en el tramo final de la serpenteante y recoleta calle de Pedro Gregorio Echeandâ”œآ،a y centrada en la fachada del antiguo nâ”¬â•‘ 20 de esa calle, abandonado hacâ”œآ،a tiempo. Al poco serâ”œآ،a derribado, conservando la pared exterior hasta la altura de la planta calle. Asâ”œآ، permaneciâ”œâ”‚ hasta que en 2017 se iniciâ”œâ”‚ la construcciâ”œâ”‚n de un edificio residencial de cuatro plantas para 55 viviendas y 67 plazas de garaje, ademâ”œأ­s de varios locales comerciales, en los casi 1500 metros cuadrados de la manzana delimitada entre la avenida de Câ”œآ®sar Augusto y las calles de San Pablo y Echeandâ”œآ،a. A la derecha, medianera con el nâ”¬â•‘ 18 de la calle, que perdura. Fuente visual: AMZ.', 1995, 1995, 1995, 'Anos 90', 'CASCO HISTâ”œأ´RICO', 41.65539300, -0.88478400, '0101000020E610000022C500892650ECBF7F83F6EAE3D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/40609576275.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/40609576275.webp', 'https://www.flickr.com/photos/zaragozaantigua/40609576275/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25853, 'Calle de Basilio Boggiero 1993', 'Imagen capturada en la calle de Basilio Boggiero a la altura del inmueble del nâ”¬â•‘ 28 ocupado por el Salâ”œâ”‚n Oasis, activo como referente de la farâ”œأ­ndula zaragozana desde su inauguraciâ”œâ”‚n en 1909 como Royal Concert. En su fachada destaca el gran mural que en 1980 pintaran Sergio Abraâ”œآ،n Gracia y Miguel â”œأ¼ngel Encuentra Villamana. Ya desde los aâ”œâ–’os 80 el cambio en las costumbres del ocio urbano y la acelerada degradaciâ”œâ”‚n social y urbanâ”œآ،stica del entorno hicieron que la decadencia de este establecimiento culminara en diciembre de 1994 con su cierre, quedando como discoteca de fin de semana. Al fondo, solares que flanquean el arranque de la calle de Pedro Echeandâ”œآ،a. Por la derecha emerge una de las torrecillas de la iglesia de Santo Tomâ”œأ­s de Aquino o de los Escolapios.', 1993, 1993, 1993, 'Anos 90', 'CASCO HISTâ”œأ´RICO', 41.65518200, -0.88581500, '0101000020E6100000B8CCE9B29858ECBFC576F700DDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50436273228.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50436273228.webp', 'https://www.flickr.com/photos/zaragozaantigua/50436273228/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25854, 'Calle del Conde de Aranda 1996', 'Imagen del aspecto de la calle del Conde Aranda (antigua del Portillo) desde su comienzo desde el cruce con la avenida de Câ”œآ®sar Augusto, al fondo, donde se destaca el colegio de los Escolapios y la fachada de la Audiencia Terrirorial, en el arranque del tramo alto del Coso. La escena ha sido capturada a la altura del cruce con la calle de Mariano Cerezo (antigua de los Aguadores), donde el paso de peatones de primer tâ”œآ®rmino.', 1996, 1996, 1996, 'Anos 90', 'CASCO HISTâ”œأ´RICO', 41.65505400, -0.88775700, '0101000020E61000003B71395E8168ECBF978E39CFD8D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50437087796.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50437087796.webp', 'https://www.flickr.com/photos/zaragozaantigua/50437087796/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25857, 'Plaza de San Pablo 1878', 'Imagen capturada desde cierta altura en la plaza de San Pablo por el fotâ”œâ”‚grafo villanovense Gregorio Sabatâ”œآ® Fâ”œآ®rriz e integrada en el â”œأ­lbum "Vistas de Zaragoza", centrada en la iglesia parroquial de San Pablo Apâ”œâ”‚stol. La imponente fachada luce la pâ”œآ®trea mâ”œأ­scara que le fue adosada al muro original durante una reforma de finales del siglo XVIII, flanqueando el ingreso de la puerta de San Pablo de finales del siglo XVI. Justo encima de ella, sobre la cornisa, icono de San Pablo aâ”œâ–’adido en 1858 y tallado por Antonio Palao. A la izquierda y hacia el fondo despuntan las cupulillas de las capillas de Santiago, San Miguel y de Nâ”¬آ¬. Sâ”¬آ¬. del Pâ”œâ”‚pulo. A la derecha, câ”œâ•‘pula de la capilla de San Pedro y San Pablo. Del conjunto emerge la impresionante atalaya del templo, posiblemente la primera torre de planta octogonal construida en ladrillo y yeso en todo el occidente europeo durante la taifa de Saraqusta (siglo XI), luego reconvertida en torre tras la conquista cristiana con varios recrecimientos en los siglos XIII, XVI y XVII, y culminada en 1859 con el chapitel y veleta que luce en la imagen, proyectado por Josâ”œآ® de Yarza Echenique.', 1878, 1878, 1878, 'Siglo XIX', 'CASCO HISTâ”œأ´RICO', 41.65600800, -0.88620100, '0101000020E610000002D71533C25BECBF0AF5F411F8D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54764908200.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54764908200.webp', 'https://www.flickr.com/photos/zaragozaantigua/54764908200/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25875, 'Palacio de la Condesa de Bureta 1848', 'L''Espagne pittoresque, artistique et monumentale. Manuel de Cuendâ”œآ،as y V. de Fâ”œآ®râ”œآ®al. Paris, 1848. Dibujo que toma como modelo otro de 1837 (www.flickr.com/photos/zaragozaantigua/20709111276) en el que se ve en primer plano a la derecha la casa-palacio de la Condesa de Bureta, Marâ”œآ،a de la Consolaciâ”œâ”‚n Domitila Azlor y Villavicencio (1773-1814), considerada heroâ”œآ،na de los Sitios de Zaragoza (1808-1809). La direcciâ”œâ”‚n actual del solar es Torre Nueva 2, Zaragoza: lugar que ocuparon los almacenes SEPU (Sociedad Espaâ”œâ–’ola de Precio â”œأœnico) y hoy edificio de viviendas. Al fondo, la Torre Nueva, en la plaza de San Felipe, mucho mâ”œأ­s inclinada de lo que estaba, para mayor espectacularidad de la estampa. Fuente: www.facebook.com/photo.php?fbid=1569173149969072&set=...', 1848, 1848, 1848, 'Siglo XIX', 'CASCO HISTâ”œأ´RICO', 41.65533100, -0.88303200, '0101000020E610000080492A53CC41ECBF0987DEE2E1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15451579300.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15451579300.webp', 'https://www.flickr.com/photos/zaragozaantigua/15451579300/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23753, 'Castillo de Alfocea 2006', 'Imagen de los restos del castillo de Alfocea, en este barrio rural de Zaragoza. A la izquierda se observa la tapia que rodea al cementerio que ocupa su solar. El nombre deriva de Al-Hauz (finca de descanso), que es como se conocâ”œآ،a el lugar en el momento de elevarse la fortaleza musulmana, que forma parte del conjunto que rodeaba la ciudad de Saraqusta. Fue ocupado por el ejâ”œآ®rcito cristiano que tomâ”œâ”‚ Zaragoza en 1118. Reconvertido en ermita de Santa Ana, en el siglo XIX ya se dedicâ”œâ”‚ a cementerio. Fuente: www.zaragoza.es', 2006, 2006, 2006, 'Siglo XXI', NULL, 41.72363300, -0.95008300, '0101000020E6100000C689AF761467EEBF37A79201A0DC4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19246174294.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19246174294.webp', 'https://www.flickr.com/photos/zaragozaantigua/19246174294/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25878, 'Alteraciones 1843', 'Grabado acerca de las revueltas en Zaragoza, 1843. En la Zaragoza de 1843 se produjeron dos pronunciamientos militares, en junio y en septiembre. El que ilustra el dibujo fue el primero, durante la regencia del General Espartero. Fue sofocado por la oposiciâ”œâ”‚n de la tropa, el pueblo y las autoridades locales. En la imagen, en primer plano a la derecha la casa-palacio de la Condesa de Bureta, Marâ”œآ،a de la Consolaciâ”œâ”‚n Domitila Azlor y Villavicencio (1773-1814), considerada heroâ”œآ،na de los Sitios de Zaragoza (1808-1809). La direcciâ”œâ”‚n actual del solar es Torre Nueva 2, Zaragoza: lugar que ocuparon los almacenes SEPU (Sociedad Espaâ”œâ–’ola de Precio â”œأœnico) y hoy edificio de viviendas. Al fondo, la Torre Nueva, en la plaza de San Felipe, mucho mâ”œأ­s inclinada de lo que estaba, para mayor espectacularidad de la estampa. Fuente: Illustrated London News, 19 de agosto de 1843.', 1843, 1843, 1843, 'Siglo XIX', 'CASCO HISTâ”œأ´RICO', 41.65600800, -0.88323500, '0101000020E610000088D7F50B7643ECBF0AF5F411F8D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19836053439.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19836053439.webp', 'https://www.flickr.com/photos/zaragozaantigua/19836053439/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25879, 'Torre Nueva 1837', '"Leaning Tower of Saragossa", dibujo de David Roberts (1796/1864). Viajâ”œâ”‚ por Espaâ”œâ–’a en 1832 y 1833. Grabado por Henry Adlard publicado en Londres en 1837 por Robert Jennings & Co. En el grabado podemos ver la Torre Nueva con una exagerada inclinaciâ”œâ”‚n, desde la perspectiva de la calle Torre Nueva, con el palacio de la Condesa de Bureta (primer edificio de la derecha). Fuente: www.facebook.com/photo.php?fbid=10206852722334632&set...', 1837, 1837, 1837, 'Siglo XIX', 'CASCO HISTâ”œأ´RICO', 41.65533100, -0.88303200, '0101000020E610000080492A53CC41ECBF0987DEE2E1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20709111276.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20709111276.webp', 'https://www.flickr.com/photos/zaragozaantigua/20709111276/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25885, 'Torre Nueva 1837', 'Litografâ”œآ،a de Jules Huyot realizada hacia 1865 y titulada "Tour inclinâ”œآ®e â”œأ، Saragosse", una nueva versiâ”œâ”‚n del clâ”œأ­sico grabado "Leaning Tower of Saragossa" de David Roberts. Respecto del original cambian los figurinistas y el atrezo urbano, y perdura la llamativa inclinaciâ”œâ”‚n de la Torre Nueva capturada desde la homâ”œâ”‚nima calle, destacando a la derecha la antigua casa de los condes de Bureta. Fuente visual: www.cortesaragon.es/', 1837, 1837, 1837, 'Siglo XIX', 'CASCO HISTâ”œأ´RICO', 41.65533100, -0.88303200, '0101000020E610000080492A53CC41ECBF0987DEE2E1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26166286408.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26166286408.webp', 'https://www.flickr.com/photos/zaragozaantigua/26166286408/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25931, 'Calle de Cerdâ”œأ­n 1952', 'Imagen capturada en la calle de Juan Jimâ”œآ®nez Cerdâ”œأ­n, antigua de la Albarderâ”œآ،a, centrada en la tranviaria unidad nâ”¬â•‘ 152 de la lâ”œآ،nea 7 &quot;Ayuntamiento-Portillo&quot; dirigiâ”œآ®ndose a la terminal de la plaza de Espaâ”œâ–’a. Esta unidad estuvo en servicio hasta la clausura de la lâ”œآ،nea en 1959, pasando luego a la lâ”œآ،nea 1 &quot;Bajo Aragâ”œâ”‚n&quot;. Fue desguazada en 1970. De fondo edilicio, la calle de Cerdâ”œأ­n a la altura de la calle de Felipe Perena (a la derecha, fuera de plano), posiblemente en el tramo de los nâ”œâ•‘meros 17 a 27, con sus referenciales bajos comerciales. Es curioso que, sin trâ”œأ­fico rodado ni aparcamiento en superficie, muchas de las tradicionales calles de la ciudad parecen ensancharse de forma mâ”œأ­gica, de forma que incluso la presencia del tranvâ”œآ،a tiene su espacio. Y el comercio de proximidad, las tiendas de toda la vida, sin afecciones o menoscabo de su actividad. Fuente visual: Josâ”œآ® Marâ”œآ،a Valero Suâ”œأ­rez, Centenario del tranvâ”œآ،a elâ”œآ®ctrico. Zaragoza, 1902-2002.', 1952, 1952, 1952, 'Anos 50', 'CASCO HISTâ”œأ´RICO', 41.65477500, -0.88411900, '0101000020E61000000FB6D8EDB34AECBF849ECDAACFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/41315982345.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/41315982345.webp', 'https://www.flickr.com/photos/zaragozaantigua/41315982345/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25969, 'Vista aâ”œآ®rea 1925', 'Vista por encima del hombro de la ciudad, focalizando el entorno del decumano maximo romano, desde la calle Manifestaciâ”œâ”‚n, pasando por Espoz y Mina, hasta la calle Mayor. La imagen capta el estado de la zona antes del Plan de Reforma Interior de 1939. Apenas visible, al fondo, la zona donde serâ”œأ­ abierta la calle S. Vicente de Paâ”œâ•‘l, actuando sobre 30.000 m2, derribando 154 construcciones de los siglos XVI-XVII (entre ellas, la casa-palacio de Sora, y La Enseâ”œâ–’anza). Mucho mâ”œأ­s visible, en el centro, las plazas de la Seo, el Pilar, y s. Juan de los Panetes, reformadas mediante la intervenciâ”œâ”‚n sobre 58.000 m2, y la demoliciâ”œâ”‚n de 224 inmuebles de los siglos XVI a XVIII, entre ellos, el convento de las Angâ”œآ®licas, la casa de los Infantes del Pilar, el convento y colegio de las Mercedarias, las oficinas de la delegaciâ”œâ”‚n de Hacienda en un palacio del XVI, la iglesia de los Agustinos, o la capilla del Carmen. En este caso, el nuevo espacio resultante tendrâ”œآ،a 50 m. de ancho, y 500 m. de largo, y estarâ”œآ،a delimitado por el Pilar, la Lonja, el Palacio Arzobispal, la Seo, y 7 nuevas manzanas en las que se levantarâ”œآ،an la Casa Consistorial, el Gobierno Civil, los Juzgados, la Hospederâ”œآ،a del Pilar, y el Colegio de Infantes, entre otras. Otras construcciones, como la iglesia de S. Juan y S. Pedro, no tuvieron que esperar a un plan de reforma en concreto para ser extinguidas, allâ”œأ­ por los felices aâ”œâ–’os 60 del pasado siglo. No se ha demostrado que en nada de esto tuvieran algo que ver los franceses. Fuente visual: J. Ortâ”œآ،z Echagâ”œâ•‌e, "Espaâ”œâ–’a. Pueblos y Paisajes".', 1925, 1925, 1925, 'Anos 20', 'CASCO HISTâ”œأ´RICO', 41.65499000, -0.88502100, '0101000020E61000002FBE688F1752ECBF809A5AB6D6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14852987862.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14852987862.webp', 'https://www.flickr.com/photos/zaragozaantigua/14852987862/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25986, 'Vista San Pablo c.1985', 'Foto colecciâ”œâ”‚n particular Celia Sâ”œأ­nchez, hacia 1985. Vista del barrio de San Pablo desde el edificio de la calle del Conde de Aranda 94-96. En primer plano, la torre de la iglesia de San Pablo y su caserâ”œآ،o circundante. Al fondo, el Pilar, la iglesia de Santa Isabel y la Seo. Fuente: www.facebook.com/photo.php?fbid=1493185717610553&set=...', 1985, 1985, 1985, 'Anos 80', 'CASCO HISTâ”œأ´RICO', 41.65536500, -0.88603400, '0101000020E61000002C9CA4F9635AECBFB6F81400E3D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15525164919.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15525164919.webp', 'https://www.flickr.com/photos/zaragozaantigua/15525164919/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23756, 'Iglesia de Alfocea 1995', 'Foto Gonzalo Bullâ”œâ”‚n, 1995. Iglesia de la Inmaculada de Alfocea, edificio barroco de 1683. Fuente: Zaragoza. Guâ”œآ،a de arquitectura. CAI, 2005.', 1995, 1995, 1995, 'Anos 90', NULL, 41.72414600, -0.95113400, '0101000020E610000023A30392B06FEEBFBDC3EDD0B0DC4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20118210355.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20118210355.webp', 'https://www.flickr.com/photos/zaragozaantigua/20118210355/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20930, 'Casa de Argillo 1564', '"Fachada de la casa de los Condes de Argillo de Zaragoza". Dibujo de Valentâ”œآ،n Carderera y Solano, realizado en 1855, con una vista parcial de la fachada del original y renacentista palacio que los Condes de Argillo poseâ”œآ،an en la calle Mayor, cerca de la iglesia parroquial de Nâ”¬آ¬ Sâ”¬آ¬ de Marâ”œآ،a Magdalena, tal vez esquinero con la calle de las Cuatro Esquinas. Como el autor anotâ”œâ”‚ posteriormente, en la parte inferior izquierda del dibujo, esta casa fue "Demolida" aâ”œâ–’os despuâ”œآ®s de capturarla con el lâ”œأ­piz. El primer conde de Argillo se habâ”œآ،a instalado en este caserâ”œâ”‚n a finales del siglo XVIII, y uno de sus descendientes heredâ”œâ”‚ luego el tâ”œآ،tulo y propiedades del marquâ”œآ®s de Villaverde, entre ellas, el palacio sito en la plaza de San Felipe, que comenzâ”œâ”‚ a ser denominado tambiâ”œآ®n, por ello, palacio de Argillo. El derribo del edificio de la calle Mayor, sobre 1860, ayudâ”œâ”‚ a simplificar las cosas, y el equâ”œآ،voco en las denominaciones. En la imagen, la fachada ha sido ambientada con una evocadora figura femenina de los tiempos de Felipe II. Fuente visual: ceres.mcu.es/', 1564, 1564, 1564, 'Siglo XIX', 'CASCO HISTâ”œأ´RICO', 41.65269900, -0.87488100, '0101000020E61000006E895C7006FFEBBFE2900DA48BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24886570752.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24886570752.webp', 'https://www.flickr.com/photos/zaragozaantigua/24886570752/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21441, 'Vista desde la Magdalena c.1910', 'Imagen del caserâ”œآ،o urbano capturada desde la altura de la aparentemente barroca torre de la iglesia parroquial de Santa Marâ”œآ،a Magdalena, orientada hacia el occidente siguiendo la traza del antiguo "decumano maximo", identificado con la estrecha cinta oscura de la calle Mayor, a la izquierda. En primer tâ”œآ®rmino, tejados recayentes a la perpendicular calle de Tomâ”œأ­s Fermâ”œآ،n Lezaun, que comunica con la paralela calle de Don Juan de Aragâ”œâ”‚n, en cuyo nâ”¬â•‘ 15 estuvo ubicada la primera escuela municipal de niâ”œâ–’as, luego sede de la Escuela Normal de Maestras; y en el nâ”¬â•‘ 11-13, la luminosa y gran estructura del colegio de la Compaâ”œâ–’â”œآ،a de las Hijas de la Caridad de San Vicente de Paâ”œâ•‘l, notablemente ampliado en 1909 para albergar el Asilo de la Coronaciâ”œâ”‚n para niâ”œâ–’os precarios. Hacia el fondo y a la derecha, techumbre, cimborrio y torre de la Seo; el templo del Pilar con sus dos torres recayentes a la homâ”œâ”‚nima plaza. Mâ”œأ­s al fondo, meandro de Ranillas y el râ”œآ،o Ebro curveando su cauce.', 1910, 1910, 1910, 'Anos 10', 'CASCO HISTâ”œأ´RICO', 41.65331800, -0.87476400, '0101000020E610000009FB761211FEEBBFAEF199EC9FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/48885788507.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/48885788507.webp', 'https://www.flickr.com/photos/zaragozaantigua/48885788507/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21787, 'Proyecto calle de la Yedra 1937', 'Proyecto de ampliaciâ”œâ”‚n de la zona afectada por la apertura de la calle de la Yedra. Nuevas expropiaciones. Regino Borobio, Zaragoza, enero de 1937. Aunque el proyecto de arrasar esa zona de la ciudad, desde el Coso Medio a la altura de la calle de la Yedra hasta el paseo del Ebro data de 1869, con nuevos intentos en 1887 y 1905, las obras de demoliciâ”œâ”‚n de edificios comenzaron en 1936. Aunque la destrucciâ”œâ”‚n mâ”œأ­s significativa se dio en la dâ”œآ®cada de los 40, la calle de San Vicente de Paâ”œâ•‘l se terminâ”œâ”‚ en 15 aâ”œâ–’os, en junio de 1951. Mide 550 metros de largo y 15 de ancho. Fuente visual: Zaragoza, espacio histâ”œâ”‚rico. Ayuntamiento de Zaragoza, 2006.', 1937, 1937, 1937, 'Anos 30', 'CASCO HISTâ”œأ´RICO', 41.65285500, -0.87547400, '0101000020E61000001BF2CF0CE203ECBFDA03ADC090D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23823914519.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23823914519.webp', 'https://www.flickr.com/photos/zaragozaantigua/23823914519/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21867, 'Calle de Argensola 1934', 'Imagen capturada en el arranque de la calle de Argensola desde la plaza de San Pedro Nolasco, con detalle de los diversos comercios ubicados en los primeros nâ”œâ•‘meros pares. En el antiguo nâ”œâ•‘mero 6, con la fachada revocada, la antigua casa de los Albiâ”œâ”‚n, luego de los Argensola, y en la que naciera Fernando Garcâ”œآ،a Mercadal en 1896. Hacia la izquierda, fuera de plano, la calle de San Juan, conducente a la iglesia parroquial de San Juan y San Pedro. Fuente visual: www.mecd.gob.es/.', 1934, 1934, 1934, 'Anos 30', 'CASCO HISTâ”œأ´RICO', 41.65313200, -0.87675900, '0101000020E61000004128EFE3680EECBF4CFC51D499D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/36422199616.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/36422199616.webp', 'https://www.flickr.com/photos/zaragozaantigua/36422199616/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21951, 'Calle de Don Juan de Aragâ”œâ”‚n 1949', 'Imagen parcial del traumatismo ocasionado por el bisturâ”œآ، urbanâ”œآ،stico que abriâ”œâ”‚ la nueva calle para coches de San Vicente de Paâ”œâ•‘l durante la dâ”œآ®cada de los cuarenta del pasado siglo XX. En este caso, la calle de Don Juan de Aragâ”œâ”‚n ha sido seccionada para conectar lo que durante siglos estuvo separado: la antigua plaza del Reino (a la derecha, desaparecida) y la calle de Lezaâ”œâ•‘n, antes del Fierro (a la izquierda, desaparecida). Todo el caserâ”œآ،o de la zona fue derribado para amoldarse a la nueva traza, excepto el palacio de los Lazâ”œأ­n (a la derecha), que tuvo la fortuna de coincidir justo con la ortogonal y nueva arteria vial. Al resto le sucediâ”œâ”‚ lo que a los edificios de la imagen: derribo, vallado, y construcciâ”œâ”‚n de nuevos edificios amoldados a la calle. En ese solar se estâ”œأ­ comenzando a levantar el nuevo colegio de la Compaâ”œâ–’â”œآ،a de las Hijas de la Caridad de San Vicente de Paâ”œâ•‘l, cuya esquina chaflaneada caracteriza hoy la zona. Al fondo, se elevan la torre nueva del Pilar, y la veterana de la Seo. Entre ambas, las traseras de los edificios de las calles Lucero y Deâ”œأ­n. Fuente visual: Archivo Mora, AMZ.', 1949, 1949, 1949, 'Anos 40', 'CASCO HISTâ”œأ´RICO', 41.65348300, -0.87490400, '0101000020E6100000797764AC36FFEBBFF9BEB854A5D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18740664341.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18740664341.webp', 'https://www.flickr.com/photos/zaragozaantigua/18740664341/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21956, 'Calle Mayor c.1943', 'Dibujo de Ambrosio Ruste de la calle Mayor, antes de ser cortada por el ensanche y prolongaciâ”œâ”‚n de la calle de la Yedra. A la izquierda, entre las calles Cedro y Lezaâ”œâ•‘n, la fachada de la casa del conde de Torreflorida, en los nâ”œâ•‘mero 43 y 45, derribada en 1942. Al fondo, la torre de la iglesia de la Magdalena, con su chapitel barroco. Fuente: â”¬أ­Aquâ”œآ،... Zaragoza!, Josâ”œآ® Blasco Ijazo, 1950.', 1943, 1943, 1943, 'Anos 40', 'CASCO HISTâ”œأ´RICO', 41.65300200, -0.87510800, '0101000020E610000098F90E7EE200ECBF7E1CCD9195D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20003915511.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20003915511.webp', 'https://www.flickr.com/photos/zaragozaantigua/20003915511/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (26077, 'Parque Primo de Rivera 1963', 'Imagen capturada sobrevolando el antiguo parque de Buenavista (entonces denominado parque de Primo de Rivera) con una vista centrada en parte del recorrido establecido con motivo de la disputa del XII Gran Premio Internacional motorista "Nâ”¬آ¬. Sâ”¬آ¬. del Pilar" organizado por el Motor Club de Aragâ”œâ”‚n en el marco de las fiestas mayores de la ciudad en el mes de octubre de ese aâ”œâ–’o. Numeroso pâ”œâ•‘blico flanquea el alabeado tramo entre la avenida de San Sebastiâ”œأ­n y la avenida de los Bearneses. En primer tâ”œآ®rmino, huertos municipales donde aâ”œâ–’os despuâ”œآ®s se ubicarâ”œآ،a el nuevo Jardâ”œآ،n Botâ”œأ­nico de la ciudad. Hacia el fondo y tras el paseo de Mariano Renovales, feraz zona agrâ”œآ،cola delimitada entre al antiguo camino del Sâ”œأ­bado (tramo luego redenominado calle del Arzobispo Morcillo), donde destaca el Grupo Residencial Salduba, y el antiguo camino viejo de Cuarte (actual calle de Julio Cejador Frauca), donde a la derecha destaca una vista parcial de la harinera "La Imperial de Aragâ”œâ”‚n".', 1963, 1963, 1963, 'Anos 60', 'UNIVERSIDAD', 41.63415200, -0.89400100, '0101000020E6100000E6EB32FCA79BECBFB4588AE42BD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/53271470291.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/53271470291.webp', 'https://www.flickr.com/photos/zaragozaantigua/53271470291/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22407, 'Calle Mayor 1968', 'Imagen en 1968 de la calle Mayor donde arranca, inmediata y hacia la izquierda, la calle Cedro, y donde desemboca, desde la derecha, la calle de los hermanos Argensola. Este tramo de la calle estaba siendo realineado, de forma que un buen nâ”œâ•‘mero de antiguos inmuebles de la acera de los pares estaban siendo sustituidos por otros mâ”œأ­s modernos. En el momento de capturar esta imagen, por ejemplo, en la esquina con Argensola, el solar de los antiguos 28-30 (luego 18), ya derribado, ejercâ”œآ،a transitoria y graciosamente como estacionamiento "duty free". La casona del antiguo 32, con la visual despejada, recuerda la monumental tipologâ”œآ،a de edificios que una vez caracterizara esta notable calle. A este edificio tambiâ”œآ®n le llegarâ”œآ،a su San Martâ”œآ،n, y serâ”œآ،a sustituido por otra cosa. Al fondo, despunta la torre de la iglesia parroquial de Santa Marâ”œآ،a Magdalena, reciâ”œآ®n despojada de sus barrocos atavâ”œآ،os. A la izquierda, cartel del filme "La mujer indomable" (The Taming of the Shrew), con el dâ”œâ•‘o Taylor & Burton, proyectada en el "Pax", ademâ”œأ­s de un buen muestrario de râ”œâ”‚tulos y carteles de establecimientos de la zona. La impactante y notable sensaciâ”œâ”‚n de caâ”œآ،da libre, conforme la calle se aproxima a la iglesia parroquial, al fondo, tiene su explicaciâ”œâ”‚n altimâ”œآ®trica en los dos metros de desnivel que hay entre ambos puntos. Fuente: "Zaragoza Viva" (1969).', 1968, 1968, 1968, 'Anos 60', 'CASCO HISTâ”œأ´RICO', 41.65355700, -0.87644800, '0101000020E6100000A1A014ADDC0BECBF33897AC1A7D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24480982941.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24480982941.webp', 'https://www.flickr.com/photos/zaragozaantigua/24480982941/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23446, 'Calle Mayor aâ”œâ–’os 20', 'Otto Wâ”œâ•‌nderlich. 1920-1936. "Zaragoza. Calle Mayor [La Torre de la Seo o Catedral del Salvador en su Epifanâ”œآ،a, al fondo]". Imagen capturada desde el cruce de la calle Mayor con la de Argensola. A la izquierda, entre la calle del Cedro y la de Lezaâ”œâ•‘n, la imponente fachada de la casa palacio del conde de Torreflorida, en el nâ”œâ•‘mero 43-45, derribada en 1942. Al fondo, la silueta de la torre de la iglesia de la Magdalena (no de La Seo). Fuente visual: Archivo Wâ”œâ•‌nderlich ( WUN-05814) www.mcu.es/fototeca_patrimonio/Visor?usarVisorMCU=true&am...', 1920, 1920, 1929, 'Anos 20', 'CASCO HISTâ”œأ´RICO', 41.65300200, -0.87510800, '0101000020E610000098F90E7EE200ECBF7E1CCD9195D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15060746781.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15060746781.webp', 'https://www.flickr.com/photos/zaragozaantigua/15060746781/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23452, 'Calle Mayor c.1935', 'AHPZ. Juan Mora Insa. "Zaragoza, calle Mayor. Alero, [del palacio] Conde de Torreflorida. Estilo: Renacimiento." En la extensa nâ”œâ”‚mina de construcciones de los siglos XVI-XVII de la ciudad que no han llegado a ver el siglo XXI, se encuentra la Casa o Palacio del Conde de Torreflorida, localizado en el nâ”¬â–‘ 43-45 de la calle Mayor, en el tramo entre la del Cedro y la de Lezaâ”œâ•‘n. En enero de 1936, la publicaciâ”œâ”‚n del SIPA "Aragâ”œâ”‚n" todavâ”œآ،a glosaba la magnificiencia de sus "miradores", o galerâ”œآ،a de arquillos del alero volado de madera, en estilo gâ”œâ”‚tico-mudâ”œآ®jar. El Palacio serâ”œآ،a piqueteado en 1942. En la imagen, el lado largo del alero daba a la calle Mayor.', 1935, 1935, 1935, 'Anos 30', 'CASCO HISTâ”œأ´RICO', 41.65292900, -0.87492500, '0101000020E6100000567DAEB662FFEBBF14CE6E2D93D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15159220638.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15159220638.webp', 'https://www.flickr.com/photos/zaragozaantigua/15159220638/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23458, 'Palacio de Torreflorida 1942', 'Portada plateresca en el Palacio de Torreflorida. 1942. La casa palacio de Torreflorida, en el nâ”œâ•‘mero 43-45 de la calle Mayor, tenâ”œآ،a una interesante portada plateresca y un patio de dos cuerpos, ademâ”œأ­s de amplios salones y jardines donde brillaba una fuente renacentista de varios surtidores. Todo esto fue piqueteado, junto con sus "miradores", o galerâ”œآ،a de arquillos del alero volado de madera, en estilo gâ”œâ”‚tico-mudâ”œآ®jar. Corrâ”œآ،a el aâ”œâ–’o de 1942. Fuente: "Zaragoza: visiones de una ciudad", Ayto. Zaragoza, 2004.', 1942, 1942, 1942, 'Anos 40', 'CASCO HISTâ”œأ´RICO', 41.65292900, -0.87492500, '0101000020E6100000567DAEB662FFEBBF14CE6E2D93D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16189847619.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16189847619.webp', 'https://www.flickr.com/photos/zaragozaantigua/16189847619/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23564, 'Calle San Lorenzo c.1965', 'Dibujo recreando la antigua casona esquinera en la confluencia de la calle del Salvaje (desde la izquierda) en la de San Lorenzo, parroquia de la Magdalena. Se trataba de una construcciâ”œâ”‚n en el estilo popular que desde los siglos XVI-XVII caracterizaba muchos de los edificios habitacionales de la ciudad, con posteriores reformas en el XVIII y XIX. Ocupaba los antiguos 42 y 44 accesorio de la calle San Lorenzo, y el 11 de la calle de los Estudios (redenominaciâ”œâ”‚n de la del Salvaje), y estuvo en pie hasta que a finales de los aâ”œâ–’os 60 la manzana San Lorenzo-Estudios-Espino fue actualizada en buena parte de sus construcciones. Desde 1970, en su lugar, se levanta el actual 15-17 de la calle de los Estudios. A su derecha, perdura el actual nâ”¬â•‘ 30 de la calle San Lorenzo, edificio de la misma â”œآ®poca, que nos ofrece la posibilidad de imaginar câ”œâ”‚mo era el edificio de la imagen, denominado "Casa Caliba". Fuente visual: "Recordando Zaragoza: obra grâ”œأ­fica, ilustrada con viâ”œâ–’etas entre textos, y diez dibujos de Rafael Margalâ”œآ®". Imagen amablemente proporcionada por Josâ”œآ® Luis Cintora.', 1965, 1965, 1965, 'Anos 60', 'CASCO HISTâ”œأ´RICO', 41.65217000, -0.87455900, '0101000020E6100000D384ED2763FCEBBF56B77A4E7AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23191076269.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23191076269.webp', 'https://www.flickr.com/photos/zaragozaantigua/23191076269/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23575, 'Calle San Lorenzo aâ”œâ–’os 30', 'Acuarela de Ambrosio Ruste, con la calle de San Lorenzo y la de los Estudios a la izquierda. Fuente: Lâ”œأ­minas de A. Ruste. Ayuntamiento de Zaragoza, 1977.', 1930, 1930, 1939, 'Anos 30', 'CASCO HISTâ”œأ´RICO', 41.65214900, -0.87455200, '0101000020E610000034D8D47954FCEBBF3F8F519E79D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32400482876.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32400482876.webp', 'https://www.flickr.com/photos/zaragozaantigua/32400482876/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24535, 'Calle de San Vicente de Paâ”œâ•‘l 1951', 'Imagen capturada en la calle San Lorenzo y centrada en el reciâ”œآ®n inaugurado Mercado de San Vicente de Paâ”œâ•‘l, proyectado por los arquitectos Josâ”œآ® de Yarza y Josâ”œآ® Beltrâ”œأ­n en la manzana ubicada entre la homâ”œâ”‚nima calle que le da nombre, en primer tâ”œآ®rmino y las calles de San Lorenzo (derecha), Pedro Calixto Ramâ”œآ،rez (al fondo), y Mayor (izquierda). Construido en ladrillo y revestido de piedra de Calatorao en su cuerpo inferior y fachada principal, su versiâ”œâ”‚n definitiva fue despojada de los remates con veletas sobre chapiteles o agujas que le daban un tono mâ”œأ­s tradicionalista y menos moderno. Los accesos a los bloques de viviendas laterales tambiâ”œآ®n fueron modificados, y dispuestos en los chaflanes laterales. Al fondo y a la derecha, vista parcial del antiguo inmueble del nâ”¬â•‘ 2 de la calle de Pedro Calixto Ramâ”œآ،rez, derribado a finales de los prodigiosos aâ”œâ–’os sesenta y sustituido por otro mâ”œأ­s moderno. A la derecha, vista parcial del inmueble del nâ”¬â•‘ 28 de la calle de San Vicente de Paâ”œâ•‘l, con su torreâ”œâ”‚n chaflanero aâ”œâ–’adido tras una reciente reforma.', 1951, 1951, 1951, 'Anos 50', 'CASCO HISTâ”œأ´RICO', 41.65275300, -0.87535500, '0101000020E6100000897B2C7DE802ECBFD5AE09698DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50099567163.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50099567163.webp', 'https://www.flickr.com/photos/zaragozaantigua/50099567163/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24904, 'Termas de Caesar Augusta siglo I', 'â”œأ«poca de Tiberio. 14-37 d.C. Detalle del frigidarium o piscina de agua frâ”œآ،a de los baâ”œâ–’os pâ”œâ•‘blicos o termas de Caesar Augusta. Estaba pavimentada con losas de mâ”œأ­rmol, sâ”œâ”‚lo conservadas en algunas zonas. La excavaciâ”œâ”‚n arqueolâ”œâ”‚gica de las termas se conserva musealizada en los bajos del nâ”œâ•‘mero 7 de la actual calle de San Juan y San Pedro. Fuente: Catâ”œأ­logo Aquaria. DPZ, 2006', 50, NULL, 99, 'Siglo XIX', 'CASCO HISTâ”œأ´RICO', 41.65339300, -0.87716900, '0101000020E6100000AD1402B9C411ECBFB937BF61A2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18487820168.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18487820168.webp', 'https://www.flickr.com/photos/zaragozaantigua/18487820168/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (26063, 'Vista 1903', 'Imagen del caserâ”œآ،o urbano capturada desde la altura de la entonces barroca torre de la iglesia parroquial de Santa Marâ”œآ،a Magdalena, orientada hacia el occidente siguiendo la traza del antiguo "decumano maximo", identificado con la estrecha cinta oscura de la calle Mayor, a la izquierda. En primer tâ”œآ®rmino, tejados recayentes a la perpendicular calle de Tomâ”œأ­s Fermâ”œآ،n Lezaun, que comunica con la paralela calle de Don Juan de Aragâ”œâ”‚n, en cuyo nâ”¬â•‘ 15 estuvo ubicada la primera escuela municipal de niâ”œâ–’as, luego sede de la Escuela Normal de Maestras; y en el nâ”¬â•‘ 11-13, la estructura del colegio de la Compaâ”œâ–’â”œآ،a de las Hijas de la Caridad de San Vicente de Paâ”œâ•‘l, en una imagen antes de su gran ampliaciâ”œâ”‚n de 1909 para albergar el Asilo de la Coronaciâ”œâ”‚n para niâ”œâ–’os precarios. Hacia el fondo y a la derecha, techumbre, cimborrio y torre de la Seo sobre el frondoso fondo de la arboleda de Macanaz; el templo del Pilar con la torre de Santiago recayente a la homâ”œâ”‚nima plaza. Mâ”œأ­s al fondo, meandro de Ranillas y el râ”œآ،o Ebro curveando su cauce.', 1903, 1903, 1903, 'Anos 1900', 'CASCO HISTâ”œأ´RICO', 41.65345100, -0.87482900, '0101000020E6100000CFF4126399FEEBBFED444948A4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49129512537.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49129512537.webp', 'https://www.flickr.com/photos/zaragozaantigua/49129512537/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20888, 'Apariciâ”œâ”‚n de la Virgen a Santiago aâ”œâ–’o 40', 'El apâ”œâ”‚stol Santiago y sus discâ”œآ،pulos adorando a la Virgen del Pilar, â”œâ”‚leo sobre lienzo, Francisco de Goya, 1775. Escena pintada por Goya para la basâ”œآ،lica del Pilar que, sin embargo, permaneciâ”œâ”‚ en manos de la Fundaciâ”œâ”‚n Rosillo hasta que la subastâ”œâ”‚ en 2011. Y es que, como decâ”œآ،a don Francisco, "En hablando de pintura y Zaragoza, me quemo vivo". El momento representado es aquâ”œآ®l del 2 de enero del aâ”œâ–’o 40 en que, segâ”œâ•‘n la tradiciâ”œâ”‚n, mientras Santiago y sus discâ”œآ،pulos rezaban a orillas del Ebro, junto a las murallas romanas, "Marâ”œآ،a Santâ”œآ،sima vino en carne mortal a Zaragoza", acompaâ”œâ–’ada de unos â”œأ­ngeles portadores de una columna de jaspe de regalo, sobre la que (como vemos), se posâ”œâ”‚ la madre de Jesâ”œâ•‘s, cual Simeâ”œâ”‚n el Estilita. Fuente: somoszaragoza.wordpress.com/2011/03/11/el-apostol-santiag...', NULL, NULL, NULL, NULL, 'CASCO HISTâ”œأ´RICO', 41.65726000, -0.87757900, '0101000020E61000001901158E2015ECBF077C7E1821D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14996824859.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14996824859.webp', 'https://www.flickr.com/photos/zaragozaantigua/14996824859/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22229, 'La Romareda c.1957', 'El reciâ”œآ®n inaugurado estadio municipal de La Romareda, en una imagen capturada desde la tribuna este, con vista parcial de la grada de gol sur, a la izquierda, que confronta con el convento de Jerusalâ”œآ®n, y de la tribuna oeste. Al fondo, el moderno Seminario Metropolitano, tras la carretera de Valencia y algunas de las torres que la jalonaban entre campos de cultivo.', 1957, 1957, 1957, 'Anos 50', 'UNIVERSIDAD', 41.63622900, -0.90259500, '0101000020E6100000520FD1E80EE2ECBF26E2ADF36FD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49877267146.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49877267146.webp', 'https://www.flickr.com/photos/zaragozaantigua/49877267146/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20983, 'Escorredero de los Puentecitos 1832', '"Mapa topogrâ”œأ­fico hidrâ”œأ­ulico que representa con todas sus particularidades câ”œâ”‚mo se halla al presente una porciâ”œâ”‚n de terreno a derecha e izquierda de la acequia o escorredero del tâ”œآ®rmino del Rabal llamado los Puentecitos y camino de la Arboleda de Macanaz y Herederos en las inmediaciones del Arrabal de Zaragoza", Antonio Vicente y Juan Mendoza, 10 de marzo de 1832. Tramo de la red de acequias de la margen izquierda de Zaragoza, en el que se instalâ”œâ”‚ un lavadero. A la izquierda, fuera de plano, el râ”œآ،o Ebro, entre el puente de Piedra y la arboleda de Macanaz (arriba). A la derecha, confluencia del escorredero de la Ortilla y el de las Balsas de Ebro Viejo. Fuente: AMZ.', 1832, 1832, 1832, 'Siglo XIX', 'CASCO HISTâ”œأ´RICO', 41.65886700, -0.87676200, '0101000020E610000086048C2E6F0EECBFF2B4FCC055D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21033067406.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21033067406.webp', 'https://www.flickr.com/photos/zaragozaantigua/21033067406/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20998, 'El Pilar c.1805', 'Grabado realizado por Francisco â”œأ¬â”œâ–’iguez Almech que captura el saliente momento de una "Procesiâ”œâ”‚n en la Capilla de la Virgen de la Basâ”œآ،lica del Pilar de Zaragoza", con el magnâ”œآ،fico enmarque escâ”œآ®nico de la Capilla de la Virgen diseâ”œâ–’ada por Ventura Rodrâ”œآ،guez a finales del siglo XVIII, que solucionaba la inserciâ”œâ”‚n del espacio de la antigua Capilla dentro de la cobertura barroca del nuevo templo del Pilar por medio de un esmerado conjunto arquitectâ”œâ”‚nico sumamente ingenioso. Fuente visual: Escuela Tâ”œآ®cnica Superior de Arquitectura de la Universidad de Navarra.', 1805, 1805, 1805, 'Siglo XIX', 'CASCO HISTâ”œأ´RICO', 41.65663800, -0.87814400, '0101000020E61000004AB72572C119ECBFCAA7C7B60CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/39383962864.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/39383962864.webp', 'https://www.flickr.com/photos/zaragozaantigua/39383962864/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21004, 'El Pilar c.1860', 'Colecciâ”œâ”‚n Madrazo, Madrid; familia Daza Campos, Madrid (Adquirido en 2006 por el Museo del Prado). Autor anâ”œâ”‚nimo. Antes de 1880. "Vista posterior de la Basâ”œآ،lica del Pilar de Zaragoza." Aâ”œâ•‘n no ha sido construida la câ”œâ•‘pula central. En la parte del râ”œآ،o, montones de maderos apilados (secâ”œأ­ndose) para la obra del Pilar. Son maderos que eran bajados desde el navarro valle del Roncal, por râ”œآ،os como el Aragâ”œâ”‚n, y el Ebro. La câ”œâ•‘pula central fue levantada entre 1866 y 1869, de forma que la fecha datada ("antes de 1880") es muy cierta.', 1860, 1860, 1860, 'Siglo XIX', 'CASCO HISTâ”œأ´RICO', 41.65691400, -0.87812300, '0101000020E61000006CB1DB679519ECBF6C2409C215D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14723211268.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14723211268.webp', 'https://www.flickr.com/photos/zaragozaantigua/14723211268/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
