INSERT INTO public.photos VALUES (21071, 'RIberas del Ebro 1871', '"Zaragoza. Riberas del Ebro", dibujo de Francisco Pradilla, 1871. Al fondo, la margen izquierda del râ”œآ،o Ebro a su paso por Zaragoza, con el convento de San Lâ”œأ­zaro. A la derecha, el puente de Piedra. Fuente: carlosurzainqui.blogspot.com.es/2013/07/el-ebro-un-rio-de...', 1871, 1871, 1871, 'Siglo XIX', 'CASCO HISTâ”œأ´RICO', 41.65665700, -0.87718800, '0101000020E61000005D328E91EC11ECBF41D829560DD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19017070455.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19017070455.webp', 'https://www.flickr.com/photos/zaragozaantigua/19017070455/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21163, 'El Pilar c.1890', 'Vista del râ”œآ،o Ebro y su margen derecha, tomada desde el puente de Piedra de Zaragoza. Se ve el palacio de Ayerbe, las Casas de los Infantes y la basâ”œآ،lica del Pilar. Fuente: Corbis Corporation', 1890, 1890, 1890, 'Siglo XIX', 'CASCO HISTâ”œأ´RICO', 41.65677600, -0.87701800, '0101000020E6100000431B800D8810ECBF1B66683C11D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20679993359.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20679993359.webp', 'https://www.flickr.com/photos/zaragozaantigua/20679993359/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21211, 'Paseo del Ebro c.1906', 'Un coche pasa bien despacito por la Ribera. No tiene marcas, pero "tos" saben que es la burguesâ”œآ،a. Hemos volteado horizontalmente la imagen original, para que la tradiciâ”œâ”‚n mariana no quede descolocada, y se precipite la fin del mundo. Fuente visual: Estudio Coyne (DARA-AHPZ).', 1906, 1906, 1906, 'Anos 1900', 'CASCO HISTâ”œأ´RICO', 41.65669200, -0.87724000, '0101000020E6100000FCC6D79E5912ECBFBDC5C37B0ED44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14964907111.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14964907111.webp', 'https://www.flickr.com/photos/zaragozaantigua/14964907111/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21280, 'Ebro y Pilar 1900', 'Postal "Zaragoza. Templo del Pilar". editada y publicada por la fototipia de Lucas Escolâ”œأ­ para la Uniâ”œâ”‚n Postal Universal. La imagen captura la fachada al Ebro, desde la catedral de la Seo al templo del Pilar con la torre de Santiago (1715) recrecida y culminada unos aâ”œâ–’os antes.', 1900, 1900, 1900, 'Anos 1900', 'CASCO HISTâ”œأ´RICO', 41.65725000, -0.87811200, '0101000020E6100000723447567E19ECBFE3A59BC420D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24730832995.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24730832995.webp', 'https://www.flickr.com/photos/zaragozaantigua/24730832995/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21566, 'Ribera del Ebro c.1925', '"Zaragoza. Pilar von Brâ”œâ•‌cke aus [El Pilar desde el Puente]". Desde la altura de las ordenadas piedras del tardomedieval puente de la ciudad sobre el Ebro, un vistazo hacia su margen derecha, con irrepetibles capturas, como la densa arboleda fluvial, y las estacas clavadas en el lecho del râ”œآ،o que conformaban antiguas represas para mejorar el rendimiento de los molinos sobre el puente. Por encima del Palacio de los Marqueses de Ayerbe, despunta una de las dos originales câ”œâ•‘pulas que culminaban con aires franceses el comercial Pasaje del Ciclâ”œâ”‚n, antes de su consunciâ”œâ”‚n durante el incendio de 1926. Fuente visual: Archivo Wâ”œâ•‌nderlich (WUN-05819) www.mcu.es/fototeca_patrimonio/Visor?usarVisorMCU=true&am...', 1925, 1925, 1925, 'Anos 20', 'CASCO HISTâ”œأ´RICO', 41.65677600, -0.87701800, '0101000020E6100000431B800D8810ECBF1B66683C11D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23209810293.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23209810293.webp', 'https://www.flickr.com/photos/zaragozaantigua/23209810293/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21797, 'Pilar c.1938', 'Imagen capturada desde un aeroplano en vuelo a baja altura sobre el Ebro y centrada en la ribereâ”œâ–’a fachada del templo del Pilar. Al fondo, a la izquierda, una insâ”œâ”‚lita visual de la torre de la desaparecida iglesia parroquial de San Juan y San Pedro, esquinera con la calle del Refugio. Fuente visual: www.todocoleccion.net/', 1938, 1938, 1938, 'Anos 30', 'CASCO HISTâ”œأ´RICO', 41.65663800, -0.87814400, '0101000020E61000004AB72572C119ECBFCAA7C7B60CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25409042087.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25409042087.webp', 'https://www.flickr.com/photos/zaragozaantigua/25409042087/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
