INSERT INTO public.photos VALUES (21822, 'Râ”œآ،o Ebro aâ”œâ–’os 30', 'Dos grupos de personas bien diferenciados pasean en barca por el râ”œآ،o Ebro en Zaragoza. El remo marca la barrera social. Fuente: Heraldo de Aragâ”œâ”‚n.', 1930, 1930, 1939, 'Anos 30', 'CASCO HISTâ”œأ´RICO', 41.65810900, -0.87811600, '0101000020E6100000CD04C3B98619ECBF051A6CEA3CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31993169606.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31993169606.webp', 'https://www.flickr.com/photos/zaragozaantigua/31993169606/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21892, 'Paseo del Ebro 1930', 'Imagen capturada en el hermoseado paseo del Ebro tras la finalizaciâ”œâ”‚n del proyecto de embellecimiento realizado segâ”œâ•‘n proyecto de Marcelo Carquâ”œآ®. Un destacado nâ”œâ•‘mero de viandantes transita por el paseo a la altura del templo del Pilar.', 1930, 1930, 1930, 'Anos 30', 'CASCO HISTâ”œأ´RICO', 41.65698600, -0.87745700, '0101000020E610000043AED4B32014ECBF06F7031E18D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49916655388.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49916655388.webp', 'https://www.flickr.com/photos/zaragozaantigua/49916655388/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21930, 'Ribera del Ebro nevada c.1946', 'Ayuntamiento de Zaragoza/Gerardo Sancho Ramo (SF). Panorâ”œأ­mica pergeâ”œâ–’ada para la ocasiâ”œâ”‚n, en una composiciâ”œâ”‚n inâ”œآ®dita, democrâ”œأ­tica, cientâ”œآ،fica y popular, generada en los laboratorios del', 1946, 1946, 1946, 'Anos 40', 'CASCO HISTâ”œأ´RICO', 41.65672400, -0.87662600, '0101000020E610000071581AF8510DECBFC83F33880FD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14921469982.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14921469982.webp', 'https://www.flickr.com/photos/zaragozaantigua/14921469982/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21980, 'El Pilar aâ”œâ–’os 40', 'Ilustraciâ”œâ”‚n representando la basâ”œآ،lica del Pilar de Zaragoza, vista desde el râ”œآ،o Ebro. Inserta al principio del documental "Por el camino de la jota" (Francisco Centol, 1957). Fuente: www.flickr.com/photos/zaragozaantigua/25597475636/in/date...', 1940, 1940, 1949, 'Anos 40', 'CASCO HISTâ”œأ´RICO', 41.65705500, -0.87832800, '0101000020E6100000A2276552431BECBF2E56D4601AD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25464475613.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25464475613.webp', 'https://www.flickr.com/photos/zaragozaantigua/25464475613/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22070, 'Hielo en el Ebro 1956', 'Febrero de 1956. Un viento polar recorre la ciudad de Zaragoza. Tan frâ”œآ،o, que los viejos del lugar recuerdan 1956 como "el aâ”œâ–’o de los cierzos heladores". En la imagen, visual cercana de los tormazos de hielo en el râ”œآ،o Ebro y al fondo la margen izquierda y el puente de Piedra. Fuente: www.facebook.com/photo.php?fbid=1499530760298019&set=...', 1956, 1956, 1956, 'Anos 50', 'CASCO HISTâ”œأ´RICO', 41.65747800, -0.87796800, '0101000020E6100000A7E7DD585018ECBF74EB353D28D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15200254584.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15200254584.webp', 'https://www.flickr.com/photos/zaragozaantigua/15200254584/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22192, 'Motos en el Pilar 1954', 'Festival del humor. Miembros del Moto Club Aragâ”œâ”‚n pasan en sus motos con sidecar santiguâ”œأ­ndose ante el camarâ”œآ،n de la Virgen del Pilar, blandiendo una pancarta con el nombre del club. Formaban parte del desfile de deportistas que a pie, en bicicleta o en motocicletas, tuvo lugar la medianoche del 9 al 10 de octubre como acto programado dentro del Congreso Mariano celebrado ese aâ”œâ–’o. Esta insâ”œâ”‚lita y ruidosa procesiâ”œâ”‚n motociclista entrâ”œâ”‚ al templo por el paseo de Echegaray y Caballero y saliâ”œâ”‚ por la plaza del Pilar. El Moto Club Aragâ”œâ”‚n fue fundado en 1922 por Luis Aperte, Josâ”œآ® Luis Saâ”œâ–’udo, Ramâ”œâ”‚n Citoler y Fernando de Yarza, â”œآ®ste padre de Pilar, luego presidenta de Heraldo de Aragâ”œâ”‚n. Los alcaldes Cesâ”œأ­reo Alierta y Luis Gâ”œâ”‚mez Laguna fueron tambiâ”œآ®n miembros de ese club, asâ”œآ، como del Movimiento Nacional. Fuente: Moto Club Aragâ”œâ”‚n.', 1954, 1954, 1954, 'Anos 50', 'CASCO HISTâ”œأ´RICO', 41.65664600, -0.87818900, '0101000020E6100000499F56D11F1AECBF4D86E3F90CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32519647586.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32519647586.webp', 'https://www.flickr.com/photos/zaragozaantigua/32519647586/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22272, 'General Batista 1962', 'Archivo Municipal. Gerardo Sancho Ramo. 30/09/1962. "Visita del General Batista". Con el dictador Fulgencio Batista, un aliado confiable y un buen amigo de Occidente, algunas empresas de los EE.UU. de norteamâ”œآ®rica poseâ”œآ،an en Cuba el 40% de las tierras azucareras, casi todas las fincas de ganado, el 90% de las concesiones mineras, el 80% de los servicios y toda la industria del petrâ”œâ”‚leo, ademâ”œأ­s de suministrar dos tercios de las importaciones del paâ”œآ،s. Mientras eso fuera asâ”œآ،, la polâ”œآ،tica interior del Râ”œآ®gimen (era una de las dictaduras mâ”œأ­s sangrientas y represivas del continente, lo que no era poco decir), era secundaria. Eran "cuestiones internas". Tras dos aâ”œâ–’os de lucha armada, fue derrocado por la Revoluciâ”œâ”‚n Cubana el 1 de enero de 1959, y huyâ”œâ”‚ de la isla con una fortuna estimada en 100 millones de dâ”œâ”‚lares. Se exiliâ”œâ”‚ primero en la Repâ”œâ•‘blica Dominicana, luego en la isla de Madeira (Portugal) y por â”œâ•‘ltimo en el Reino de Espaâ”œâ–’a, hasta su muerte (en 1973, de infarto) en el humilde municipio de Marbella. En la imagen, Fulgencio Batista (a la derecha, sin bigote), su seâ”œâ–’ora, y unos amigos, visitan a la Virgen del Pilar en sus estancias mâ”œأ­s â”œآ،ntimas (el ropero), y todos estâ”œأ­n encantadâ”œآ،simos.', 1962, 1962, 1962, 'Anos 60', 'CASCO HISTâ”œأ´RICO', 41.65685700, -0.87808500, '0101000020E61000000C76C3B64519ECBF0893E2E313D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14937754782.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14937754782.webp', 'https://www.flickr.com/photos/zaragozaantigua/14937754782/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22425, 'El Pilar c.1965', 'Vista del Pilar reflejado en el Ebro. Fuente: Foto para postal de Comercial Josan. Cesiâ”œâ”‚n de la familia de Josâ”œآ® Marâ”œآ،a Sanz Gonzâ”œأ­lez a Rafael Castillejo. Dataciâ”œâ”‚n y procesado:', 1965, 1965, 1965, 'Anos 60', 'CASCO HISTâ”œأ´RICO', 41.65725000, -0.87811200, '0101000020E6100000723447567E19ECBFE3A59BC420D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27321899712.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27321899712.webp', 'https://www.flickr.com/photos/zaragozaantigua/27321899712/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22849, 'Guardabarrera Macanaz 1985', 'Imagen de la (habitada) casa del guardabarrera de Macanaz junto al antiguo, y desmantelado, enlace ferroviario entre la Estaciâ”œâ”‚n del Norte y la Estaciâ”œâ”‚n primero de Campo Sepulcro, luego Portillo, y la de Caminreal-Delicias. Esta caseta se situaba junto al viejo Camino de Ranillas, actual Arquitecto La Figuera-Paseo de la Ribera, en su confluencia con la calle Garcâ”œآ،a Arista. Al fondo, la arboleda de Macanaz.', 1985, 1985, 1985, 'Anos 80', 'CASCO HISTâ”œأ´RICO', 41.65942200, -0.87819800, '0101000020E610000016342DB1321AECBFA721AAF067D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15215303497.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15215303497.webp', 'https://www.flickr.com/photos/zaragozaantigua/15215303497/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23229, 'El Pilar aâ”œâ–’o 3978', '"Paco Pico y Pico Vena en: Regreso al planeta de los monos", viâ”œâ–’eta probablemente dibujada por Tha para El Jueves en los aâ”œâ–’os 90 del siglo XX, parodiando a Pedro Pico y Pico Vena en la escena â”œâ•‘ltima de la pelâ”œآ،cula "El planeta de los simios" (1968). La pareja de personajes aludida (cuyo primer miembro cambia de nombre en esta versiâ”œâ”‚n) que sustituye al coronel George Taylor (Charlton Heston) es creaciâ”œâ”‚n de Carlos Azagra, dibujante que creciâ”œâ”‚ en Zaragoza. Vemos, en el lugar que en el filme ocupa la Estatua de la Libertad, la Basâ”œآ،lica del Pilar de Zaragoza, en el aâ”œâ–’o en el que transcurre la ficciâ”œâ”‚n simiesca, 3978. Fuente: cazagra.blogspot.com.es/2008/04/charlton-heston-que-ests-...', 2024, 2020, 2029, 'Siglo XXI', 'CASCO HISTâ”œأ´RICO', 41.65679500, -0.87838100, '0101000020E610000057B08D78B21BECBF9296CADB11D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15369805512.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15369805512.webp', 'https://www.flickr.com/photos/zaragozaantigua/15369805512/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23819, 'El Pilar 1862', 'Litografâ”œآ،a de M. Fuster incluida en el libro "Historia crâ”œآ،tica y apologâ”œآ®tica de la Virgen Nuestra Seâ”œâ–’ora del Pilar de Zaragoza", Madrid, 1862.', 1862, 1862, 1862, 'Siglo XIX', 'CASCO HISTâ”œأ´RICO', 41.65725000, -0.87811200, '0101000020E6100000723447567E19ECBFE3A59BC420D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18898918754.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18898918754.webp', 'https://www.flickr.com/photos/zaragozaantigua/18898918754/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23845, 'Rayo en El Pilar 1798', '"Marâ”œآ،a Santâ”œآ،sima del Pilar de Zaragoza defendiendo a sus devotos de las terribles exhalaciones que cayeron en su angâ”œآ®lica capilla la tarde del 5 de setiembre de 1798". Grabado de Mariano Latasa de 1804, editado posteriormente por Tomâ”œأ­s Rocafort. El llamado "milagro de la centella" consistiâ”œâ”‚ en que el rayo que atravesâ”œâ”‚ la basâ”œآ،lica en 1798 no daâ”œâ–’â”œâ”‚ a las personas que se encontraban allâ”œآ،. La sed de propaganda pilarista llevâ”œâ”‚ a conmemorar la fecha con celebraciones sacras en aâ”œâ–’os posteriores. En el dibujo, el rayo estâ”œأ­ representado a la derecha, recorriendo la imagen completa de arriba abajo. Fuente: Fondo Documental Histâ”œâ”‚rico de las Cortes de Aragâ”œâ”‚n.', 1798, 1798, 1798, 'Siglo XIX', 'CASCO HISTâ”œأ´RICO', 41.65665600, -0.87817700, '0101000020E6100000382EE3A6061AECBF705CC64D0DD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24469749609.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24469749609.webp', 'https://www.flickr.com/photos/zaragozaantigua/24469749609/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23847, 'El Pilar 1907', 'Foto: Petit. Basâ”œآ،lica del Pilar en el otoâ”œâ–’o de 1907, reciâ”œآ®n terminada la torre sureste. Fuente: Ministâ”œآ؟re de la Culture (France) - Mâ”œآ®diathâ”œآ؟que de l''architecture et du patrimoine.', 1907, 1907, 1907, 'Anos 1900', 'CASCO HISTâ”œأ´RICO', 41.65713500, -0.87839300, '0101000020E6100000682101A3CB1BECBF4A07EBFF1CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24575336213.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24575336213.webp', 'https://www.flickr.com/photos/zaragozaantigua/24575336213/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23849, 'El Pilar 1907', 'Foto: Lucien Roy. Vista del Pilar desde el Ebro. Acaba de levantarse la segunda torre, que aâ”œâ•‘n presenta andamios en su base. Fuente: Ministâ”œآ؟re de la Culture (France) - Mâ”œآ®diathâ”œآ؟que de l''architecture et du patrimoine.', 1907, 1907, 1907, 'Anos 1900', 'CASCO HISTâ”œأ´RICO', 41.65713500, -0.87839300, '0101000020E6100000682101A3CB1BECBF4A07EBFF1CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24851347299.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24851347299.webp', 'https://www.flickr.com/photos/zaragozaantigua/24851347299/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23860, 'Pilar c.1940', 'Fotografâ”œآ،a convertida en popular postal capturando el interior de la dieciochesca capilla diseâ”œâ–’ada por Ventura Rodrâ”œآ،guez para albergar al icono de la Virgen de Nâ”¬آ¬ Sâ”¬آ¬ del Pilar, en el templo del mismo nombre. El manto mariano que figura en la imagen fue ofrendado por Falange Espaâ”œâ–’ola para ser lucido con ocasiâ”œâ”‚n de los rituales aquâ”œآ، organizados por este partido polâ”œآ،tico, una muestra de la â”œآ،ntima y simbiâ”œâ”‚tica relaciâ”œâ”‚n de este escenario de culto con el râ”œآ®gimen surgido tras el 18 de julio de 1936. Fuente visual: www.todocoleccion.net/', 1940, 1940, 1940, 'Anos 40', 'CASCO HISTâ”œأ´RICO', 41.65665600, -0.87817700, '0101000020E6100000382EE3A6061AECBF705CC64D0DD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/29733452623.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/29733452623.webp', 'https://www.flickr.com/photos/zaragozaantigua/29733452623/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23869, 'Pilar y Fuensanta 1940', 'El aâ”œâ–’o 1940 fue prâ”œâ”‚digo en celebraciones zaragozanas nacional-catâ”œâ”‚licas, aprovechando la efemâ”œآ®ride de la legendaria Venida de la Virgen, 1.900 aâ”œâ–’os antes, y reforzando la asfixiante propaganda de los nuevos poderes, tras la derrota militar de la democracia. El 18 de septiembre, Miguel de los Santos Dâ”œآ،az y Gomara, entonces obispo de Cartagena, comandâ”œâ”‚ una peregrinaciâ”œâ”‚n desde Murcia hasta Zaragoza, portando la imagen de la Virgen de la Fuensanta, patrona de Murcia. El tren que la llevaba contaba con un vagâ”œâ”‚n especial, dotado de un altar en el que reposaba la figura. El momento que recoge la foto es el del encuentro de la Virgen del Pilar (izquierda) con la Virgen de la Fuensanta (derecha), ambas con su criatura en brazos. Curioso caso de bilocaciâ”œâ”‚n representada, provista gracias al fenâ”œâ”‚meno de la advocaciâ”œâ”‚n mariana, que oferta multitud de denominaciones al personaje, convirtiâ”œآ®ndolo en un grupo de fâ”œآ®minas mâ”œآ،ticas diferenciadas. Fuente: www.laopiniondemurcia.es/', 1940, 1940, 1940, 'Anos 40', 'CASCO HISTâ”œأ´RICO', 41.65673100, -0.87826600, '0101000020E6100000200A664CC11AECBF7BA2EBC20FD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30724684240.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30724684240.webp', 'https://www.flickr.com/photos/zaragozaantigua/30724684240/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23879, 'Huelga General 1904', 'Chiste grâ”œأ­fico realizado por Joaquâ”œآ،n Moya, publicado en la revista satâ”œآ،rica madrileâ”œâ–’a Gedeâ”œâ”‚n, en su nâ”œâ•‘mero 455, del 12 de agosto de 1904. Se hace referencia a la Huelga General de ese verano en Zaragoza. Al fondo, panorâ”œأ­mica de la ciudad, incluyendo una factorâ”œآ،a y el Pilar tras el râ”œآ،o Ebro. Fuente: Biblioteca Nacional de Espaâ”œâ–’a.', 1904, 1904, 1904, 'Anos 1900', 'CASCO HISTâ”œأ´RICO', 41.65870300, -0.87700000, '0101000020E6100000AAF1D24D6210ECBF7863416150D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31159510676.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31159510676.webp', 'https://www.flickr.com/photos/zaragozaantigua/31159510676/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23890, 'Goya en Zaragoza 1781', '"Goya en Zaragoza", dibujo de Josâ”œآ® Luis Cano que representa al pintor Francisco de Goya pintando la câ”œâ•‘pula "Regina Martyrum" en el Pilar de Zaragoza. Es câ”œآ®lebre su enfrentamiento con el cabildo a causa del estilo de esta pintura. Fuente: "Zaragoza nuestra ciudad", Ayuntamiento de Zaragoza, 1983.', 1781, 1781, 1781, 'Siglo XIX', 'CASCO HISTâ”œأ´RICO', 41.65679800, -0.87812500, '0101000020E61000009A9999999919ECBF030AF5F411D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32186749735.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32186749735.webp', 'https://www.flickr.com/photos/zaragozaantigua/32186749735/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23895, 'El cojo de Calanda 1638', 'Cuenta la leyenda que Miguel Juan Pellicer Blasco, nacido en Calanda en 1617, tuvo un accidente de carro en Castellâ”œâ”‚n en 1637, que le fracturâ”œâ”‚ la tibia derecha. Trasladado al Hospital Real de Valencia y luego al Hospital Nuestra Seâ”œâ–’ora de Gracia de Zaragoza, le amputan la pierna por estar gangrenada y la entierran en el cementerio de este â”œâ•‘ltimo hospital. En 1638 se le coloca una pierna de madera y se le surte de una muleta. Con estas armas pide limosna en la puerta del templo mudâ”œآ®jar del Pilar y entra a untarse el muâ”œâ–’â”œâ”‚n con aceite de las lâ”œأ­mparas, momento que recoge la imagen. En 1640 viaja a su pueblo natal, donde la Virgen del Pilar le repone la pierna mientras duerme, incluyendo sus antiguas marcas: un mal grano, unos rasguâ”œâ–’os y un mordisco de perro. Este fenâ”œâ”‚meno le hace famoso, hasta el punto de ser recibido por el rey, Felipe IV. Fuera el desgaste de la fama o que la Virgen del Pilar estaba ocupada en otros asuntos, Miguel falleciâ”œâ”‚ en Velilla de Ebro a los 30 aâ”œâ–’os. Pero no por eso se le olvidâ”œâ”‚: un paisano suyo, Luis Buâ”œâ–’uel, escogiâ”œâ”‚ la novela de Galdâ”œâ”‚s "Tristana" para hacer una pelâ”œآ،cula, porque â”œآ®sta perdâ”œآ،a una pierna. Y casi cuatro siglos despuâ”œآ®s, continâ”œâ•‘a habiendo muchas personas que toman por real la milagrosa anâ”œآ®cdota del cojo de Calanda. Fuente visual: Fragmento de pintura mural de la iglesia de Nuestra Seâ”œâ–’ora del Pilar en Calanda.', 1638, 1638, 1638, 'Siglo XIX', 'CASCO HISTâ”œأ´RICO', 41.65663800, -0.87814400, '0101000020E61000004AB72572C119ECBFCAA7C7B60CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/35753110784.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/35753110784.webp', 'https://www.flickr.com/photos/zaragozaantigua/35753110784/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22259, 'Campo de fâ”œâ•‘tbol de la Romareda 1960', '1960. Al fondo a la derecha, el Seminario.', 1960, 1960, 1960, 'Anos 60', 'UNIVERSIDAD', 41.63629300, -0.90183000, '0101000020E61000005DA79196CADBECBF3DD68C0C72D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14728546019.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14728546019.webp', 'https://www.flickr.com/photos/zaragozaantigua/14728546019/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23900, 'El Pilar c.1907', 'Imagen capturada en la arboleda de Macanaz y centrada en el lienzo norteâ”œâ–’o del templo del Pilar recayente a la ribera del râ”œآ،o Ebro, que fluye parsimonioso en primer tâ”œآ®rmino. La gran câ”œâ•‘pula central aparece flanqueada de las dos torres culminadas pocos aâ”œâ–’os antes. A la izquierda, tras la Puerta del Retiro Bajo, el Colegio de los Infantes del Pilar. A la derecha, el antiguo postigo de Santa Marâ”œآ،a del Pilar, sobre el que se dejan ver parcialmente las traseras de la que fuera antigua casa de Aytona.', 1907, 1907, 1907, 'Anos 1900', 'CASCO HISTâ”œأ´RICO', 41.65716200, -0.87817600, '0101000020E6100000213A048E041AECBF441669E21DD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49174723972.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49174723972.webp', 'https://www.flickr.com/photos/zaragozaantigua/49174723972/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23901, 'Asamblea Municipalista 1906', 'Dibujo satâ”œآ،rico que reproduce a los mâ”œأ­s notables dirigentes republicanos que participaron en la Asamblea Municipalista de Zaragoza, reunida entre el 9 y el 11 de febrero de 1906, en el teatro Pignatelli. Los personajes representan, cogidicos de la mano, como corresponde, el principio del "Coro y jota de los de Calatorao" que forma parte de la zarzuela "Gigantes y Cabezudos". Destaca por su tamaâ”œâ–’o, a la izquierda, Joaquâ”œآ،n Costa, seguido de Alejandro Lerroux, Marcelino Isâ”œأ­bal, Ricardo Fuente, y otros. La original letra de esta jota ("Por ver a la Pilarica, vengo de Calatoaro. Vinimos en la perrera, â”¬أ­Jesâ”œâ•‘s, lo que hemos gastao!") ha sido modificada para la ocasiâ”œâ”‚n con rimante y republicano gracejo. Al fondo, el templo del Pilar aparece con la torre de Santiago, si bien la de Nuestra Seâ”œâ–’ora del Pilar, a la izquierda, ya se encontraba en proceso de culminaciâ”œâ”‚n.', 1906, 1906, 1906, 'Anos 1900', 'CASCO HISTâ”œأ´RICO', 41.65858100, -0.87652400, '0101000020E61000006117450F7C0CECBF2C62D8614CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49203970382.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49203970382.webp', 'https://www.flickr.com/photos/zaragozaantigua/49203970382/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23972, 'Transfiguraciâ”œâ”‚n del Pilar 1974', 'Archivo Municipal de Zaragoza. Gerardo Sancho Ramo. 16/07/1974. "El Pilar." Imagen nocturna del templo mariano, cuya apariencia se hace blanca y resplandeciente, y asemeja rebosante de gloria celestial. O, en tâ”œآ®rminos fâ”œآ،sicos, simula una enana blanca (estrella frâ”œآ،a estable, mantenida por la repulsiâ”œâ”‚n debida al principio de exclusiâ”œâ”‚n entre electrones). O a lo mejor es sâ”œâ”‚lo que han encendido la luz...', 1974, 1974, 1974, 'Anos 70', 'CASCO HISTâ”œأ´RICO', 41.65686200, -0.87826100, '0101000020E6100000AE450BD0B61AECBF19FED30D14D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15127652420.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15127652420.webp', 'https://www.flickr.com/photos/zaragozaantigua/15127652420/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24772, 'C.â”¬â•‘ de Ranillas 1930', 'Apenas 15 centâ”œآ،metros por debajo de la marca de la oceâ”œأ­nica inundaciâ”œâ”‚n de 1871, la "crecida" del Ebro de marzo de 1930 fue memorable. En el Arrabal, la situaciâ”œâ”‚n fue tremenda: las viviendas prâ”œâ”‚ximas al antiguo camino de Ranillas tuvieron que ser desalojadas, y las familias refugiadas provisionalmente en la Estaciâ”œâ”‚n del Norte. La imagen, capturada desde el tendido ferroviario que conectaba Zaragoza con Alsasua, ilustra los efectos de la riada en viviendas del Arrabal tras la rotura del muro de protecciâ”œâ”‚n. Las traseras de las casas de la izquierda formaban parte de las doce construidas recientemente por la "Cooperativa Hogar Obrero", con entrada por la calle Demetrio Galâ”œأ­n (luego Garcâ”œآ،a Arista). Las viviendas de la derecha, recayentes a la zona mâ”œأ­s prâ”œâ”‚xima a la calle Sixto Celorrio. Toda esta zona llegarâ”œأ­ mâ”œأ­s o menos en estas condiciones (sin agua de inundaciâ”œâ”‚n), hasta finales de la dâ”œآ®cada de los prodigiosos sesenta, en que serâ”œأ­n derribadas las viejas casas, y sobre ellas, sus huertos y jardines traseros, y la amplia zona de huerta, se levantarâ”œأ­n los grandes bloques habitacionales de hoy en dâ”œآ،a. Las vâ”œآ،as fâ”œآ®rreas serâ”œأ­n desmanteladas. Fuente visual: A de la Barrera, revista "Estampa" (Madrid).', 1930, 1930, 1930, 'Anos 30', 'CASCO HISTâ”œأ´RICO', 41.65884700, -0.87649100, '0101000020E610000073A087DA360CECBFAB08371955D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22983190135.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22983190135.webp', 'https://www.flickr.com/photos/zaragozaantigua/22983190135/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24804, 'Crecida del Ebro 1930', 'Foto: Miguel Marâ”œآ،n Chivite. Vista de las casas del Grupo Hogar Obrero, en el camino de Ranillas del Arrabal. La imagen estâ”œأ­ tomada el 15 de marzo de 1930, durante la punta de la crecida del râ”œآ،o Ebro de ese aâ”œâ–’o. Fuente: Heraldo de Aragâ”œâ”‚n.', 1930, 1930, 1930, 'Anos 30', 'CASCO HISTâ”œأ´RICO', 41.65953900, -0.87765300, '0101000020E6100000AC8F87BEBB15ECBFE1B721C66BD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33450501536.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33450501536.webp', 'https://www.flickr.com/photos/zaragozaantigua/33450501536/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24817, 'Vista Arrabal 1930', 'Imagen capturada desde la altura de la torre de Santiago del templo del Pilar, con una interesante vista panorâ”œأ­mica del barrio del Arrabal, en la margen izquierda del râ”œآ،o Ebro. La arboleda de Macanaz aparece inundada por la crecida de ese aâ”œâ–’o. En el centro de la escena, la iglesia de Nuestra Seâ”œâ–’ora de Altabâ”œأ­s, la estaciâ”œâ”‚n del Norte ye industrias como Maquinista y Fundiciones del Ebro, S.A., la Nueva Harinera de Solans, y la azucarera del Arrabal. Hacia el fondo y a la derecha, la rectilâ”œآ،nea avenida de Cataluâ”œâ–’a se dirige al puente del Gâ”œأ­llego.', 1930, 1930, 1930, 'Anos 30', 'CASCO HISTâ”œأ´RICO', 41.65846900, -0.87626600, '0101000020E6100000761893FE5E0AECBF043752B648D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49626790638.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49626790638.webp', 'https://www.flickr.com/photos/zaragozaantigua/49626790638/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24847, 'Concurso de aviaciâ”œâ”‚n 1911', 'Foto Pelayo. Revista Nuevo Mundo, 1911. Concurso de aviaciâ”œâ”‚n con la participaciâ”œâ”‚n de los pilotos Gaget y Frey. Convocado por el Ayuntamiento, que ofreciâ”œâ”‚ como premio la Copa de Zaragoza. Uno de los aeroplanos sobrevuela el Pilar, el Ebro y la Arboleda de Macanaz.', 1911, 1911, 1911, 'Anos 10', 'CASCO HISTâ”œأ´RICO', 41.65725000, -0.87811200, '0101000020E6100000723447567E19ECBFE3A59BC420D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18944615669.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18944615669.webp', 'https://www.flickr.com/photos/zaragozaantigua/18944615669/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22382, 'Vista aâ”œآ®rea Romareda 1964', 'Vista aâ”œآ®rea centrada en el campo de fâ”œâ•‘tbol de la Romareda. A la derecha, el paseo de Isabel la Catâ”œâ”‚lica. Fuente visual : Fotografâ”œآ،a aâ”œآ®rea Lecar para el libro "El Ayuntamiento de Zaragoza", Colecciâ”œâ”‚n Rafael Margalâ”œآ®.', 1964, 1964, 1964, 'Anos 60', 'UNIVERSIDAD', 41.63637700, -0.90173500, '0101000020E6100000EC12D55B03DBECBF9B7631CD74D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22326829231.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22326829231.webp', 'https://www.flickr.com/photos/zaragozaantigua/22326829231/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24855, 'Ebrobâ”œâ•‘s 2008', 'El martes 12 de agosto de 2008 y en el marco de la Expo, fue inaugurado el servicio de barcos recreativos en el râ”œآ،o Ebro a su paso por Zaragoza, entre Vadorrey y Ranillas, bautizado como Ebrobâ”œâ•‘s (momento que recoge la imagen, con visual de los edificios del paseo de la Ribera, frente al Pilar). Como se ve en la foto, ademâ”œأ­s de los dos embarcaderos en las ubicaciones citadas, se habilitâ”œâ”‚ un tercero en los bajos del Club Nâ”œأ­utico. Para conseguir que el cauce fuese navegable, se construyâ”œâ”‚ en 2007 el azud Manuel Lorenzo Pardo, que en un principio iba a estar dotado de una estaciâ”œâ”‚n elâ”œآ®ctrica para aprovechar el salto de agua (descartada) y que tambiâ”œآ®n sirve de pasarela peatonal entre Las Fuentes y Vadorrey (â”œâ•‘nico uso que permanece). En octubre de ese mismo 2008 se inaugurâ”œâ”‚ una nueva tradiciâ”œâ”‚n pilarista: la Ofrenda Fluvial, procedente de Vadorrey y aprovechando este nuevo medio de transporte que pretendâ”œآ،a emular a los Bateaux Mouches parisinos. Tras sus â”œâ•‘ltimos viajes en 2015, el servicio fue cancelado definitivamente en 2016, habida cuenta de que los câ”œأ­lculos tâ”œآ®cnicos acerca de la lâ”œأ­mina de agua necesaria resultaron errados y era necesario dragar el cauce una y otra vez, sin conocimiento. La Ofrenda Fluvial permanece, en embarcaciones mâ”œأ­s ligeras. Fuente visual: araclasicas.blogspot.com', 2008, 2008, 2008, 'Siglo XXI', 'CASCO HISTâ”œأ´RICO', 41.65708700, -0.87683700, '0101000020E61000002F87DD770C0FECBF39D0436D1BD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31182062015.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31182062015.webp', 'https://www.flickr.com/photos/zaragozaantigua/31182062015/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25105, 'Calle de Garcâ”œآ،a Arista 1930', 'Imagen de â”œأ¼ngel Bagâ”œâ•‌â”œآ®s, profesional barquero que conducâ”œآ،a una embarcaciâ”œâ”‚n en el paso del Ebro que conectaba el pretil junto a San Juan de los Panetes hasta la arboleda de Macanaz, y que fue publicitado como "hâ”œآ®roe de las inundaciones" por sus labores de rescate realizadas durante la gran salida de madre del râ”œآ،o en marzo de 1930 (sâ”œâ”‚lo quince centâ”œآ،metros menos de altura que la monstruosa de 1871), cuando entre otras acciones condujo unos pontones hasta el Acampo de Urzâ”œأ­iz, en Movera, para rescatar a varias personas encaramadas en lo alto de una tapia durante toda la noche a la espera de socorro. Preguntado por el nâ”œâ•‘mero de personas rescatadas en el râ”œآ،o durante toda su vida, estimaba que "mâ”œأ­s de un centenar". La foto fue realizada en su humilde vivienda inmediata al râ”œآ،o en la calle de Gregorio Garcâ”œآ،a Arista. En poco tiempo trocarâ”œآ،a la tradicional barca de sirga de toda la vida por una moderna "gasolinera".', 1930, 1930, 1930, 'Anos 30', 'CASCO HISTâ”œأ´RICO', 41.65910200, -0.87742500, '0101000020E61000006B2BF697DD13ECBF355D4F745DD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52204216129.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52204216129.webp', 'https://www.flickr.com/photos/zaragozaantigua/52204216129/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25114, 'Bella perspectiva del Pilar 1982', 'Antonio Fraguas de Pablo, Forges, 1982. Ilustraciâ”œâ”‚n aparecida en la obra vendida por fascâ”œآ،culos "Con ustedes... Forges ''82", sobre el Mundial de fâ”œâ•‘tbol de ese aâ”œâ–’o.', 1982, 1982, 1982, 'Anos 80', 'CASCO HISTâ”œأ´RICO', 41.65686200, -0.87826100, '0101000020E6100000AE450BD0B61AECBF19FED30D14D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15035056736.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15035056736.webp', 'https://www.flickr.com/photos/zaragozaantigua/15035056736/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25444, 'Ribera Ebro 1950', 'Bajo la tercera arcada del puente de Piedra, que originalmente fue la cuarta, una vista parcial de la obra del nuevo ayuntamiento y del templo del Pilar con dos torres: la de Santiago, a la derecha, iniciada en 1715 y terminada en 1892, y la de Nuestra Seâ”œâ–’ora del Pilar, a la izquierda, construida entre 1903 y 1907. Del cauce del râ”œآ،o sobresalen lâ”œآ،neas de estacas que recuerdan las que reforzaban el azud o presa que encauzaba agua hacia los antiguos molinos harineros establecidos en el puente, entre ellos el molino de la ciudad. En la orilla del râ”œآ،o se observa un ir y venir de gente buscando el refresco de la sombra y el agua. Hacia el fondo y a la derecha, la pasarela peatonal y las pilastras del puente del Ferrocarril. Fuente visual: www.ebay.es/', 1950, 1950, 1950, 'Anos 50', 'CASCO HISTâ”œأ´RICO', 41.65683500, -0.87628700, '0101000020E6100000541EDD088B0AECBF20EF552B13D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31408029645.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31408029645.webp', 'https://www.flickr.com/photos/zaragozaantigua/31408029645/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25456, 'Râ”œآ،o Ebro c.1950', 'Imagen del râ”œآ،o Ebro centrada en el templo del Pilar y sus tradicionales torres recayentes a la homâ”œâ”‚nima plaza. Hacia el fondo, obras de construcciâ”œâ”‚n de la nueva Casa Consistorial sobre extenso solar donde estuviera, entre otros inmuebles, el palacio de los marqueses de Ayerbe. Una barca navega en direcciâ”œâ”‚n a la pasarela de Macanaz, cuya sombra se perfila sobre el tranquilo cauce fluvial.', 1950, 1950, 1950, 'Anos 50', 'CASCO HISTâ”œأ´RICO', 41.65673700, -0.87821900, '0101000020E6100000F33977BB5E1AECBF5D8940F50FD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49552670461.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49552670461.webp', 'https://www.flickr.com/photos/zaragozaantigua/49552670461/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25500, 'El Pilar 1877', 'Jean Laurent. 1877 "Iglesia de Nuestra Seâ”œâ–’ora del Pilar." De detalles, a veces, tambiâ”œآ®n estâ”œأ­ hecha la imagen: conjunciâ”œâ”‚n cupulativa con la â”œâ•‘nica torre incompleta, y Postigo de Aguadores o de Blancas.', 1877, 1877, 1877, 'Siglo XIX', 'CASCO HISTâ”œأ´RICO', 41.65668900, -0.87764000, '0101000020E6100000842A357BA015ECBF4C5299620ED44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15277775005.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15277775005.webp', 'https://www.flickr.com/photos/zaragozaantigua/15277775005/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25555, 'Arboleda de Macanaz 1907', 'Foto: Lucien Roy. Arboleda de Macanaz en la margen izquierda del râ”œآ،o Ebro. Al fondo, el puente de Piedra y la torre de la Seo. Fuente: Ministâ”œآ؟re de la Culture (France) - Mâ”œآ®diathâ”œآ؟que de l''architecture et du patrimoine.', 1907, 1907, 1907, 'Anos 1900', 'CASCO HISTâ”œأ´RICO', 41.65882000, -0.87802700, '0101000020E6100000E5284014CC18ECBFB1F9B83654D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24847320929.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24847320929.webp', 'https://www.flickr.com/photos/zaragozaantigua/24847320929/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25562, 'Vista aâ”œآ®rea râ”œآ،o Ebro 1957', 'Vista aâ”œآ®rea del râ”œآ،o Ebro a su paso por Zaragoza, con la plaza del Pilar a la derecha y la pasarela de Macanaz abajo. Fuente: TAF Helicâ”œâ–“pters. Arxiu Nacional de Catalunya.', 1957, 1957, 1957, 'Anos 50', 'CASCO HISTâ”œأ´RICO', 41.65757400, -0.87814200, '0101000020E61000001CCF6740BD19ECBF965984622BD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30550100153.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30550100153.webp', 'https://www.flickr.com/photos/zaragozaantigua/30550100153/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25572, 'El Pilar 1908', 'Imagen estereoscâ”œâ”‚pica capturada desde el puente de Piedra y centrada en el templo del Pilar. A la izquierda, el colegio de los Infantes del Pilar y jardines de la casa de los marqueses de Ayerbe. A la derecha y hacia el fondo, la iglesia de San Juan de los Panetes.', 1908, 1908, 1908, 'Anos 1900', 'CASCO HISTâ”œأ´RICO', 41.65702600, -0.87800500, '0101000020E6100000F12E17F19D18ECBF944F8F6D19D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51425415660.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51425415660.webp', 'https://www.flickr.com/photos/zaragozaantigua/51425415660/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (26057, 'Râ”œآ،o Ebro 1938', 'Imagen capturada desde un aeroplano Heinkel 45-F 2 de la Legiâ”œâ”‚n Câ”œâ”‚ndor en funciones de reconocimiento sobrevolando la ribera del râ”œآ،o Ebro sobre el Arrabal. En primer tâ”œآ®rmino, la arboleda de Macanaz y la casilla del enlace ferroviario. Centra la escena la tradicional fachada edilicia de la margen derecha desde el puente de Piedra hasta la Puerta del Fin, con el templo del Pilar en medio.', 1938, 1938, 1938, 'Anos 30', 'CASCO HISTâ”œأ´RICO', 41.65768300, -0.87701700, '0101000020E61000002D27A1F48510ECBF4D11E0F42ED44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33386230721.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33386230721.webp', 'https://www.flickr.com/photos/zaragozaantigua/33386230721/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (26074, 'Râ”œآ،o Ebro c. 1900', 'Imagen capturada en la margen izquierda del râ”œآ،o Ebro, entre el puente de Piedra y el comienzo de la alameda de Macanaz, y centrada en el templo del Pilar con su torre de Santiago. A la izquierda, la casa de los marqueses de Ayerbe y la de los Infantes del Pilar, por la que asoma una de las câ”œâ•‘pulas del pasaje de la Industria y el Comercio. A la derecha, la torre de la iglesia de San Pablo Apâ”œâ”‚stol, el torreâ”œâ”‚n de la Zuda y la torre y cupulilla de la iglesia de San Juan de los Panetes, tras la que se abrâ”œآ،a la Puerta de San Ildefonso.', 1900, 1900, 1900, 'Anos 1900', 'CASCO HISTâ”œأ´RICO', 41.65728200, -0.87825100, '0101000020E6100000CBBC55D7A11AECBFEF1F0BD121D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51666365183.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51666365183.webp', 'https://www.flickr.com/photos/zaragozaantigua/51666365183/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20939, 'El Pilar 1778', 'Dibujo realizado por el arquitecto Fernando Martâ”œآ،nez Corcâ”œآ،n de los volâ”œâ•‘menes exteriores proyectados por Ventura Rodrâ”œآ،guez, y en buena parte no realizados, para la iglesia del Pilar, en este caso centrada en la fachada recayente a la ribera del Ebro. Destaca el ingreso principal establecido en el centro de la fachada, la soledad de la câ”œâ•‘pula del coro, a la derecha, y la altura y remate de las torres de las esquinas. Flanquean al templo, a la izquierda, la Casa de los Infantes, cercana a las Casas de la Ciudad; y a la derecha, los almacenes prâ”œâ”‚ximos a la iglesia de San Juan de Malta o de los Panetes.', 1778, 1778, 1778, 'Siglo XIX', 'CASCO HISTâ”œأ´RICO', 41.65679800, -0.87852000, '0101000020E6100000B0389CF9D51CECBF030AF5F411D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/45767943864.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/45767943864.webp', 'https://www.flickr.com/photos/zaragozaantigua/45767943864/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20955, 'Zaragoza 1806', '"Nuestra Seâ”œâ–’ora del Pilar en Zarragossa", dibujo de Lejeune grabado por Daudet, 1806. La ciudad de Zaragoza, con el Puente de Piedra sobre el Ebro, la Seo y el Pilar. Aparece representada la iglesia de San Juan del Puente, al inicio de â”œآ®ste. Y bajo la arcada central puede verse el torreâ”œâ”‚n de Monserrate, que se levantaba sobre el estribo derecho del Puente de Tablas. Fuente: â”œأ¼lbum grâ”œأ­fico de Zaragoza, 1985', 1806, 1806, 1806, 'Siglo XIX', 'CASCO HISTâ”œأ´RICO', 41.65888300, -0.87877900, '0101000020E6100000B22B2D23F51EECBFF871344756D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15262551954.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15262551954.webp', 'https://www.flickr.com/photos/zaragozaantigua/15262551954/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20989, 'Alegorâ”œآ،a de Zaragoza 1818', 'â”œأ´leo sobre lienzo con el boceto del telâ”œâ”‚n de boca del Teatro Principal de Zaragoza. Cristâ”œâ”‚bal Garrigo, 1818. Alegorâ”œآ،a clâ”œأ­sica en la que Zaragoza, vestida como Palas, es conducida al Parnaso por Apolo y Talâ”œآ،a. A la derecha, la fuente Castalia y las tres musas Calâ”œآ،ope, Erato y Polimnia, que entregan sus aguas a un viejo, el râ”œآ،o Ebro. En el centro, Melpâ”œâ”‚mene y tres de sus geniecillos; Euterpe y Terpsicore. Abajo a la izquierda, los delitos y los vicios son lanzados al Averno. Mâ”œأ­s arriba, Clâ”œآ،o, el Tiempo y Urania. Arriba a la derecha, Pegaso vuela junto al templo de la Fama en la cima del monte Parnaso. Al fondo a la izquierda, el templo del Pilar. Arriba, dos angelotes sostienen el escudo nobiliario de la marquesa de Lazâ”œأ­n, a la que estâ”œأ­ dedicada la obra. Fuente: Actas del curso "Arte del siglo XIX", IFC, 2013.', 1818, 1818, 1818, 'Siglo XIX', 'CASCO HISTâ”œأ´RICO', 41.65687500, -0.87856200, '0101000020E61000006B44300E2E1DECBFAE47E17A14D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24697071697.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24697071697.webp', 'https://www.flickr.com/photos/zaragozaantigua/24697071697/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21035, 'El Pilar 1869', 'Vista del Pilar a orillas del Ebro, con la câ”œâ•‘pula central a punto de ser terminada. Fuente: Mariano Jâ”œâ•‘dez y Ortiz. Colecciâ”œâ”‚n Antonio Arguas Perdiguer. Libro Primeros tiempos de la fotografâ”œآ،a en Zaragoza.', 1869, 1869, 1869, 'Siglo XIX', 'CASCO HISTâ”œأ´RICO', 41.65684700, -0.87854300, '0101000020E6100000BB26A435061DECBFE4BCFF8F13D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27968578614.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27968578614.webp', 'https://www.flickr.com/photos/zaragozaantigua/27968578614/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21039, 'El Pilar c.1860', 'Recreaciâ”œâ”‚n del templo del Pilar con el râ”œآ،o Ebro en primer plano, en una estampa piadosa de la casa Bonasse Lebel de Parâ”œآ،s. La inacabada torre de Santiago, con la ayuda de las palmeras, deviene en minarete. Fuente: www.delcampe.net', 1860, 1860, 1860, 'Siglo XIX', 'CASCO HISTâ”œأ´RICO', 41.65685400, -0.87850000, '0101000020E6100000E9263108AC1CECBF971FB8CA13D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/36538628395.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/36538628395.webp', 'https://www.flickr.com/photos/zaragozaantigua/36538628395/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21041, 'El Pilar 1869', '"Saragossa Cathedral, from the Ebro". Imagen del templo del Pilar capturada desde la margen izquierda, entre la vâ”œآ،a del empalme de las lâ”œآ،neas fâ”œآ®rreas de Barcelona y Pamplona y la ribera del râ”œآ،o Ebro. El angular fotogrâ”œأ­fico nos ofrece una sobresaliente panorâ”œأ­mica de este tramo de la fachada ribereâ”œâ–’a de la margen derecha, desde la casa de los marqueses de Ayerbe y el Colegio de los Infantes hasta la puerta del Fin y la iglesia de San Juan de los Panetes. En el Pilar destacan los andamios de obra en torno a la gran câ”œâ•‘pula central, en construcciâ”œâ”‚n desde 1866 con proyecto de los arquitectos Juan Antonio Atienza y Josâ”œآ® Yarza y Miâ”œâ–’ana, que serâ”œأ­ terminada en agosto de ese aâ”œâ–’o. A la derecha, la inacabada y original â”œâ•‘nica torre del termplo, denominada de Santiago, con su caracterâ”œآ،stico y provisional tejadillo a dos aguas. Sobre el Ebro, un par de barcas y el monumental reflejo de la iglesia metropolitana. En la margen derecha, la abrupta pendiente ribereâ”œâ–’a producto del depâ”œâ”‚sito artificial de materiales acumulado para ganar terreno al râ”œآ،o y hacer posible la ambiciosa ampliaciâ”œâ”‚n del Pilar emprendida en 1681. Fuente visual: Francis Frith, en J. Paul Getty Museum', 1869, 1869, 1869, 'Siglo XIX', 'CASCO HISTâ”œأ´RICO', 41.65679800, -0.87852000, '0101000020E6100000B0389CF9D51CECBF030AF5F411D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/45382125452.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/45382125452.webp', 'https://www.flickr.com/photos/zaragozaantigua/45382125452/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21087, 'El Pilar 1872', 'Dibujo del entorno de la plaza del Pilar, bastante mâ”œأ­s despejado de la realidad del momento, donde destaca la nueva figura de la iglesia metropolitana de Nuestra Seâ”œâ–’ora del Pilar tras la culminaciâ”œâ”‚n de las obras de la gran câ”œâ•‘pula central y las câ”œâ•‘pulas laterales. El entusiasmo del dibujante por la magnificencia del resultado le ha llevado a aâ”œâ–’adir, por el mismo precio, un ilusorio tercer cuerpo extra a la câ”œâ•‘pula central. A su lado, la inacabada torre de Santiago parece mâ”œأ­s demediada que nunca. Al fondo, a la izquierda, el complejo de San Juan de los Panetes. Fuente: dibujo de Ferrer, en "La vuelta por Espaâ”œâ–’a : viaje histâ”œâ”‚rico, geogrâ”œأ­fico, cientâ”œآ،fico recreativo y pintoresco : historia popular de Espaâ”œâ–’a en su parte geogrâ”œأ­fica, civil y polâ”œآ،tica... / escrita en virtud de los datos adquiridos en las mismas localidades por una sociedad de literatos" (tomo I), Barcelona, 1872.', 1872, 1872, 1872, 'Siglo XIX', 'CASCO HISTâ”œأ´RICO', 41.65685400, -0.87850000, '0101000020E6100000E9263108AC1CECBF971FB8CA13D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34077894373.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34077894373.webp', 'https://www.flickr.com/photos/zaragozaantigua/34077894373/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21173, 'Conservas Salvadâ”œâ”‚ 1897', 'Etiqueta para recipiente de conserva de tomate al natural de la fâ”œأ­brica de conservas Francisco Salvadâ”œâ”‚, sita en la calle de las Armas 14. El dibujo incluye un aspecto del Pilar. Fuente: www.todocoleccion.net', 1897, 1897, 1897, 'Siglo XIX', 'CASCO HISTâ”œأ´RICO', 41.65681400, -0.87852200, '0101000020E6100000DE205A2BDA1CECBF08C72C7B12D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31088263441.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31088263441.webp', 'https://www.flickr.com/photos/zaragozaantigua/31088263441/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
