INSERT INTO public.photos VALUES (21188, 'Cartel del Pilar 1894', 'Cartel oficial de las fiestas del Pilar de 1894. Marcelino de Unceta. Litografâ”œآ،a Portabella. Anuncia los diversos actos previstos e ncluye dibujos de aspectos de la ciudad, como el Pilar desde el paseo del Ebro, la plaza de la Constituciâ”œâ”‚n con la fuente de la Princesa o el paso de una cabalgata con una carroza. Fuente visual: Heraldo de Aragâ”œâ”‚n.', 1894, 1894, 1894, 'Siglo XIX', 'CASCO HISTâ”œأ´RICO', 41.65682200, -0.87852000, '0101000020E6100000B0389CF9D51CECBF8BA548BE12D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/38978581624.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/38978581624.webp', 'https://www.flickr.com/photos/zaragozaantigua/38978581624/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21291, 'Pilar iluminado 1908', 'Ilustraciâ”œâ”‚n de Josâ”œآ® Bueno reflejando la iluminaciâ”œâ”‚n especial del templo del Pilar en 1908, a cargo de "la casa Kribben de Madrid". Fuente: Diario ABC.', 1908, 1908, 1908, 'Anos 1900', 'CASCO HISTâ”œأ´RICO', 41.65689100, -0.87852000, '0101000020E6100000B0389CF9D51CECBFB404190115D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27320244598.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27320244598.webp', 'https://www.flickr.com/photos/zaragozaantigua/27320244598/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21301, 'Margen izquierda 1903', 'Tres caballeros posan en la margen izquierda del râ”œآ،o Ebro, con el Pilar al fondo. Fuente: Heraldo de Aragâ”œâ”‚n.', 1903, 1903, 1903, 'Anos 1900', 'CASCO HISTâ”œأ´RICO', 41.65889500, -0.87863100, '0101000020E61000008D0E48C2BE1DECBFBC3FDEAB56D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33022592561.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33022592561.webp', 'https://www.flickr.com/photos/zaragozaantigua/33022592561/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21324, 'Vista 1908', 'Imagen capturada desde la altura de la torre de Santiago del templo metropolitano del Pilar, con una vista orientada hacia el râ”œآ،o Ebro y la zona ribereâ”œâ–’a comprendida entre los puentes de Piedra y de Hierro. En primer tâ”œآ®rmino y sobre la câ”œâ•‘pula central, detalle de la decoraciâ”œâ”‚n e iluminaciâ”œâ”‚n especial diseâ”œâ–’adas por la casa Kribben de Madrid, instaladas en el Pilar con motivo de las celebraciones del centenario de los asedios de 1908-09 y la Exposiciâ”œâ”‚n Hispano-Francesa de 1908. A la derecha, la reciente torre de Nuestra Seâ”œâ–’ora del Pilar y la barroca de la Seo.', 1908, 1908, 1908, 'Anos 1900', 'CASCO HISTâ”œأ´RICO', 41.65676100, -0.87846600, '0101000020E6100000E4BB94BA641CECBFE62494BE10D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/48981579242.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/48981579242.webp', 'https://www.flickr.com/photos/zaragozaantigua/48981579242/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21350, 'El Pilar c.1900', 'Imagen capturada en la margen izquierda, junto a las vâ”œآ،as del empalme ferroviario de las lâ”œآ،neas de Barcelona y Pamplona, y centrada en una vista de la fachada fluvial del templo del Pilar.', 1900, 1900, 1900, 'Anos 1900', 'CASCO HISTâ”œأ´RICO', 41.65761600, -0.87854100, '0101000020E61000008E3EE603021DECBFC5A9D6C22CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54205319816.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54205319816.webp', 'https://www.flickr.com/photos/zaragozaantigua/54205319816/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21388, 'El Pilar 1915', 'Foto L. Cepero. Desde la basilical torre de Nâ”¬آ¬ Sâ”¬آ¬ del Pilar, bajo una mortecina luz, el râ”œآ،o Ebro y sus mâ”œأ­rgenes, la derecha edilicia, y la izquierda, despejada, en una visual irrepetible â”¬آ½أ”أ‡آھporque las estirpes condenadas a cien aâ”œâ–’os de soledad no tenâ”œآ،an una segunda oportunidad sobre la tierraâ”¬â•—. Fuente: La Esfera, 23 de octubre de 1915.', 1915, 1915, 1915, 'Anos 10', 'CASCO HISTâ”œأ´RICO', 41.65827400, -0.87892900, '0101000020E61000000531D0B52F20ECBF4FE78A5242D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19869940878.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19869940878.webp', 'https://www.flickr.com/photos/zaragozaantigua/19869940878/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21391, 'El Pilar 1918', 'Foto: Kurt Hielscher. Vista de la basâ”œآ،lica del Pilar de Zaragoza. Al fondo, la iglesia de San Juan de los Panetes y la chimenea de la Alcoholera Agrâ”œآ،cola del Pilar, junto al Ayuntamiento en la plaza de Santo Domingo. Fuente: www.facebook.com/photo.php?fbid=894087094001697&set=g...', 1918, 1918, 1918, 'Anos 10', 'CASCO HISTâ”œأ´RICO', 41.65687900, -0.87847900, '0101000020E61000000C21E7FD7F1CECBFF0366F9C14D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21150450192.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21150450192.webp', 'https://www.flickr.com/photos/zaragozaantigua/21150450192/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21489, 'Vista del Pilar 1925', 'Miguel Faci Abad. 1920-1925. "Zaragoza. Basâ”œآ،lica del Pilar". Desde la azotea del Casino Mercantâ”œآ،l, un vistazo hacia la ribera se topa con el Pilar, ademâ”œأ­s de con todo el caserâ”œآ،o urbano del momento que es fâ”œآ،sicamente posible ver, tanto a este lado del Ebro, como en el lado del Arrabal. A este lado, a la izquierda inmediata, la pequeâ”œâ–’a trinchera de la calle Blasâ”œâ”‚n Aragonâ”œآ®s y su desembocadura en la plaza de Sas. La cantidad de solanares (terrazas o galerâ”œآ،as orientadas al sol) es impresionante, y hace que el relieve de los tejados sea abrupto, como de una sierra urbana. Suaviza algo este paisaje los bulbosos remates del edificio del burguâ”œآ®s Pasaje de El Ciclâ”œâ”‚n, ya en la plaza del Pilar. Seguimos en esta ribera con los airosos remates de la Lonja, y un poco antes, la torre que se eleva de la tardo-barroca iglesia de la Exaltaciâ”œâ”‚n de la Santa Cruz. Al otro lado del râ”œآ،o, a la derecha, visual de las torrecillas de Nâ”¬آ¬ Sâ”¬آ¬ de Altabâ”œأ­s, y el par de chimeneas de la Azucarera de Aragâ”œâ”‚n, o del Arrabal. Fuente visual: "Miguel y Gabriel Faci. Fotâ”œâ”‚grafos fundadores de la Real Sociedad Fotogrâ”œأ­fica de Zaragoza.", Alfredo Romero y Ricardo Centellas, Diputaciâ”œâ”‚n Provincial de Zaragoza, 1999.', 1925, 1925, 1925, 'Anos 20', 'CASCO HISTâ”œأ´RICO', 41.65682700, -0.87847600, '0101000020E6100000C8444AB3791CECBF9D103AE812D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15149063954.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15149063954.webp', 'https://www.flickr.com/photos/zaragozaantigua/15149063954/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21504, 'Vista desde el Pilar 1925', 'Miguel Faci Abad. 1920-1925. "Zaragoza. Vista del Arrabal desde la torre vieja del Pilar". Le hemos tenido que dar la vuelta (horizontalmente) a la imagen para rescatarla del caos y la desorientaciâ”œâ”‚n en que estaba sumida, porque el tâ”œآ،tulo dice una cosa, y luego la vista era otra. Ahora se ven las cosas como si fuera Zaragoza, el puente de las Piedras y el Ebro, no Leningrado, el puente Azul y el Gran Neva. La imagen, asâ”œآ،, estâ”œأ­ capturada desde la torre de Santiago del Pilar. El puente de las Piedras, entre la gran câ”œâ•‘pula central, y la segunda câ”œâ•‘pula menor de la fachada al Ebro. Justo detrâ”œأ­s, el antiguo convento de San Lâ”œأ­zaro, en el cuartel del mismo nombre. A la izquierda, tras la arboleda de Macanaz, el Arrabal con varios elementos referenciales: la cubierta a dos vertientes de la Estaciâ”œâ”‚n del Norte; las dos torrecillas flanqueando la Iglesia de Nuestra Seâ”œâ–’ora de Altabâ”œأ­s, junto al convento de terciarias franciscanas de Altabâ”œأ­s; y las dos chimeneas de la Azucarera de Aragâ”œâ”‚n, o del Arrabal. La gran diagonal arbolada de la carretera de Cataluâ”œâ–’a conduce hasta el Gâ”œأ­llego. Fuente visual: "Miguel y Gabriel Faci. Fotâ”œâ”‚grafos fundadores de la Real Sociedad Fotogrâ”œأ­fica de Zaragoza.", Alfredo Romero y Ricardo Centellas, Diputaciâ”œâ”‚n Provincial de Zaragoza, 1999.', 1925, 1925, 1925, 'Anos 20', 'CASCO HISTâ”œأ´RICO', 41.65688100, -0.87912000, '0101000020E6100000FD4D2844C021ECBF902E36AD14D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15578579599.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15578579599.webp', 'https://www.flickr.com/photos/zaragozaantigua/15578579599/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21517, 'El Pilar c.1920', 'Casino Mercantil y Agrâ”œآ،cola. c.1920. Tras la remodelaciâ”œâ”‚n del antiguo palacio-casa de Juan de Coloma segâ”œâ•‘n proyecto de Francisco Albiâ”œâ–’ana, la directiva del Casino Mercantil y Agrâ”œآ،cola decidiâ”œâ”‚ iluminar los interiores de su nueva sede con imâ”œأ­genes alegâ”œâ”‚ricas segâ”œâ•‘n la moda Regionalista y Costumbrista del momento, acudiendo a los artistas locales mâ”œأ­s propicios. La basâ”œآ،lica concatedral no podâ”œآ،a faltar en la nâ”œâ”‚mina de asuntos iconâ”œâ”‚dulos. En la imagen, una sublimaciâ”œâ”‚n del Pilar despojada de referencias espaciales concretas, al menos en el territorio de las tres dimensiones fâ”œآ،sicas estâ”œأ­ndares. Los tonos dorados de un atardecer resplandeciente difuminan los contornos del râ”œآ،o, la ribera, el puente. La ciudad parece mâ”œأ­s ubâ”œآ®rrima que de costumbre.', 1920, 1920, 1920, 'Anos 20', 'CASCO HISTâ”œأ´RICO', 41.65682700, -0.87847600, '0101000020E6100000C8444AB3791CECBF9D103AE812D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15890488675.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15890488675.webp', 'https://www.flickr.com/photos/zaragozaantigua/15890488675/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21539, 'Arboleda de Macanaz 1929', 'La arboleda de Macanaz de Zaragoza, Luicien Roisin, 1929. Niâ”œâ–’os en la arboleda de Macanaz, en la Margen Izquierda del Ebro. Al fondo, el puente de Piedra. Fuente: "Zaragoza, aâ”œâ–’os veinte. 81 fotografâ”œآ،as de Roisin (1925-1931)", Instituciâ”œâ”‚n Fernando el Catâ”œâ”‚lico, 2014.', 1929, 1929, 1929, 'Anos 20', 'CASCO HISTâ”œأ´RICO', 41.65894200, -0.87963500, '0101000020E6100000BC57AD4CF825ECBFFDFA213658D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19904267059.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19904267059.webp', 'https://www.flickr.com/photos/zaragozaantigua/19904267059/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21727, 'El Pilar aâ”œâ–’os 30', 'Dibujo de Sidney Tushingham, aâ”œâ–’os 30 del siglo XX. Fuente: fineprintedinc.com/', 1930, 1930, 1939, 'Anos 30', 'CASCO HISTâ”œأ´RICO', 41.65682700, -0.87847600, '0101000020E6100000C8444AB3791CECBF9D103AE812D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20909430441.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20909430441.webp', 'https://www.flickr.com/photos/zaragozaantigua/20909430441/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21796, 'Cimientos del Pilar ca. 1930', '"Muralla en la pilastra nâ”œâ•‘mero 10. Templo del Pilar". Aspecto del subsuelo de la basâ”œآ،lica, bajo un emplazamiento cercano a la puerta oeste de la ribera. En 1923, Teodoro Râ”œآ،os proyectâ”œâ”‚ unas obras de mantenimiento del templo que se prolongaron hasta 1940. Incluyeron refuerzos de hormigâ”œâ”‚n, como los que se observan aquâ”œآ، sobre la muralla romana, y que comenzaron a aplicarse en 1930. Fuente: Archivo Mora, AMZ. ES. 50297. AM 04.01.01.01 Sobre 07430.', 1930, 1930, 1930, 'Anos 30', 'CASCO HISTâ”œأ´RICO', 41.65711900, -0.87866100, '0101000020E610000037A968ACFD1DECBF454AB3791CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25325501029.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25325501029.webp', 'https://www.flickr.com/photos/zaragozaantigua/25325501029/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21879, 'Pl. del Pilar 1936', 'Imagen capturada en la plaza del Pilar y centrada en el "Altar de los Caâ”œآ،dos" instalado de forma efâ”œآ،mera ante la fachada sur de la basâ”œآ،lica del Pilar, con motivo de los actos organizados en el tercer aniversario de la fundaciâ”œâ”‚n del partido polâ”œآ،tico Falange Espaâ”œâ–’ola en el Teatro de la Comedia de Madrid (29 de octubre de 1933). Tras una misas matutinas en homenaje a los falangistas muertos, por este espacio procesionaron los falangistas locales acompaâ”œâ–’ados por varios miles llegados de Logroâ”œâ–’o. Este fue un destacado acto de reafirmaciâ”œâ”‚n de la "Patria tan escarnecida por el marxismo y tan defendida con tesâ”œâ”‚n por estos hombres de las flechas y la camisa azul", celebrado en la Zaragoza levantada en armas contra la democracia a mediados de julio de ese aâ”œâ–’o. El exento conjunto simbâ”œâ”‚lico de la imagen fue instalado en el centro de la soleada fachada sur del templo del Pilar, entre las dos zonas ajardinadas y arboladas que entonces definâ”œآ،an el espacio de la recoleta plaza homâ”œâ”‚nima, confrontando directamente con el desemboque de la calle de Alfonso I. Presiden un enorme yugo y flechas como sâ”œآ،mbolos del partido polâ”œآ،tico Falange Espaâ”œâ–’ola, y la leyenda "Presente" como muestra del recuerdo al "Ausente" Josâ”œآ® Antonio Primo de Rivera.. En la dâ”œآ®cada siguiente esta fachada sur serâ”œآ،a objeto de una monumental reforma proyectada por Teodoro Râ”œآ،os Balaguer que incluirâ”œآ،a una imagen de la Virgen del Pilar en este mismo emplazamiento. Fuente visual: "Aragâ”œâ”‚n: revista grâ”œأ­fica de cultura aragonesa" (1936).', 1936, 1936, 1936, 'Anos 30', 'CASCO HISTâ”œأ´RICO', 41.65662700, -0.87890500, '0101000020E6100000E44EE960FD1FECBFD655815A0CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/44806382691.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/44806382691.webp', 'https://www.flickr.com/photos/zaragozaantigua/44806382691/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21888, 'Obras del Pilar c.1935', 'Imagen capturada desde la torre de Nuestra Seâ”œâ–’ora del Pilar con una interesante vista de la arboleda de Macanaz y el barrio del Arrabal. Al fondo, la Alcoholera del Pilar y la Uniâ”œâ”‚n Alcoholera Espaâ”œâ–’ola. En primer tâ”œآ®rmino, obra de reposiciâ”œâ”‚n del tejadillo a dos aguas del remate de la torre noreste del templo, mediante la colocaciâ”œâ”‚n de nuevas vigas de madera que luego serâ”œأ­n retejadas convenientemente.', 1935, 1935, 1935, 'Anos 30', 'CASCO HISTâ”œأ´RICO', 41.65680800, -0.87852000, '0101000020E6100000B0389CF9D51CECBF26E0D74812D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49670809646.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49670809646.webp', 'https://www.flickr.com/photos/zaragozaantigua/49670809646/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22006, 'Emblema corriente aâ”œâ–’os 40', '"Zaragoza. Pilar de la fe y columna de la patria espaâ”œâ–’ola". Anverso y reverso de un "emblema corriente" de cartâ”œâ”‚n, emitido durante la dâ”œآ®cada de los cuarenta por Auxilio Social, organizaciâ”œâ”‚n falangista de socorro humanitario y propaganda polâ”œآ،tica. Estas insignias, versiâ”œâ”‚n barata de las metâ”œأ­licas de la Alemania nazi, se entregaban a cambio de donativos obligatorios a la entrada de espectâ”œأ­culos. Fuente: www.delcampe.net', 1940, 1940, 1949, 'Anos 40', 'CASCO HISTâ”œأ´RICO', 41.65693300, -0.87869100, '0101000020E6100000E14389963C1EECBFE3546B6116D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/36894196236.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/36894196236.webp', 'https://www.flickr.com/photos/zaragozaantigua/36894196236/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22034, 'Proyecto Pilar 1948', 'Ilustraciâ”œâ”‚n para el proyecto de construcciâ”œâ”‚n de las dos torres ribereâ”œâ–’as del Pilar, presentado por el arquitecto Miguel â”œأ¼ngel Navarro Pâ”œآ®rez en 1948. En 1946, los esposos de la alta sociedad zaragozana Francisco de Borja Urzaiz y Leonor Sala decidieron financiar la construcciâ”œâ”‚n de las dos torres, cuyas primeras piedras se colocaron en 1949, aunque las obras no comenzaron hasta 1951. La del noroeste, llamada de San Francisco de Borja, se finalizâ”œâ”‚ en 1959; la otra, llamada de Santa Leonor, en 1961.', 1948, 1948, 1948, 'Anos 40', 'CASCO HISTâ”œأ´RICO', 41.65684500, -0.87855200, '0101000020E610000088BB7A15191DECBF43C5387F13D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52526949815.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52526949815.webp', 'https://www.flickr.com/photos/zaragozaantigua/52526949815/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22045, 'El Pilar 1956', 'Imagen de las dos torres en construcciâ”œâ”‚n del Pilar (nombradas de San Francisco de Borja, y de Santa Leonor, como una de las contraprestaciones a sus humanos esponsorizadores, que asâ”œآ، pasaron a la mariana posteridad) y el nuevo Ayuntamiento, tambiâ”œآ®n en fase de construcciâ”œâ”‚n. La torre de la izquierda fue acabada en 1959, y la de al derecha en 1961. El edificio del Ayuntamiento pareciâ”œâ”‚ afectado por el "mal de las obras del Pilar", pues estuvo mâ”œأ­s de veinte aâ”œâ–’os en esa tesitura (1946-1965), hasta que finalmente pudo incluirse entre los inconmensurables logros de los "25 aâ”œâ–’os de paz" del Râ”œآ®gimen. Fuente visual: DARA (AHPZ-DGA). Estudio Coyne.', 1956, 1956, 1956, 'Anos 50', 'CASCO HISTâ”œأ´RICO', 41.65668300, -0.87844600, '0101000020E61000001DAA29C93A1CECBF6A6B44300ED44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14791479228.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14791479228.webp', 'https://www.flickr.com/photos/zaragozaantigua/14791479228/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22222, 'El Pilar c.1953', 'Imagen capturada desde la arboleda de Macanaz y centrada en el templo del Pilar durante los preliminares a las obras de recrecimiento de las torres ribereâ”œâ–’as, como indican los muretes perimetrales que circunvalan la oriental torre que serâ”œأ­ denominada de San Francisco de Borja. A la izquierda, estructura de la nueva Casa Consistorial durante sus prolongadas obras de construcciâ”œâ”‚n. Sobre ella emerge la barroca torre de la Seo. En primer tâ”œآ®rmino, el râ”œآ،o Ebro fluye parsimonioso, parminedeico.', 1953, 1953, 1953, 'Anos 50', 'CASCO HISTâ”œأ´RICO', 41.65700000, -0.87875600, '0101000020E6100000A73D25E7C41EECBF6ABC749318D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/48893128741.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/48893128741.webp', 'https://www.flickr.com/photos/zaragozaantigua/48893128741/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22225, 'El Pilar c.1950', 'Imagen capturada desde la arboleda de Macanaz y centrada en el templo del Pilar poco antes del definitivo inicio de las obras de recrecimiento de las torres ribereâ”œâ–’as. A la izquierda, esqueleto hormigonado de la nueva Casa Consistorial durante su dilatado proceso de construcciâ”œâ”‚n. En primer tâ”œآ®rmino, el râ”œآ،o Ebro fluye parsimonioso, calmo, regalando la vista del acuâ”œأ­tico doppelgâ”œأ±nger pilarista.', 1950, 1950, 1950, 'Anos 50', 'CASCO HISTâ”œأ´RICO', 41.65826000, -0.87929200, '0101000020E6100000444DF4F92823ECBFEA211ADD41D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49123504361.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49123504361.webp', 'https://www.flickr.com/photos/zaragozaantigua/49123504361/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
