INSERT INTO public.photos VALUES (22298, 'Cuatro torres en el Pilar 1961', 'Clichâ”œآ® de "El Noticiero". El templo de El Pilar estrena imagen. Ya tiene cuatro torres, una en cada una de sus cuatro esquinas. Ha sido posible gracias al particular y mâ”œأ­s que generoso mecenazgo de Francisco de Urzâ”œأ­iz (ya fallecido), y Leonor Sala, que fallecerâ”œأ­ al poco. Fuente literal: "Aragâ”œâ”‚n : revista grâ”œأ­fica de cultura aragonesa" (Aâ”œâ–’o XXXV, Nâ”¬â•‘ 261, octubre-diciembre 1961).', 1961, 1961, 1961, 'Anos 60', 'CASCO HISTâ”œأ´RICO', 41.65678500, -0.87846800, '0101000020E610000012A452EC681CECBF6EC0E78711D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15509051229.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15509051229.webp', 'https://www.flickr.com/photos/zaragozaantigua/15509051229/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
