INSERT INTO public.photos VALUES (22696, 'Vista 1973', 'Panorama desde la altura de la torre "del ascensor" o de San Francisco de Borja del Pilar, con la plaza del Pilar donde destaca el aparcamiento en superficie del Gobierno Civil, y la fachada de la antigua calle de Goicoechea. A la izquierda, la Seo y su arbolada plaza. Se visualizan unas cuantas de las impactantes obras edilicias que, durante esos prodigiosos aâ”œâ–’os, levantaron moles en el antiguo casco histâ”œâ”‚rico, sin demasiados problemas, dudas, o quejas. Despuntan tambiâ”œآ®n las torres de la Magdalena, San Carlos, San Pedro Nolasco, y la câ”œâ•‘pula de Santa Cruz. En primer tâ”œآ®rmino, las jaculatorias de neâ”œâ”‚n sobre câ”œâ•‘pulas y torres como acompaâ”œâ–’amiento textual al tradicional "bendita y alabada sea la hora", que suena tres veces al dâ”œآ،a desde su inauguraciâ”œâ”‚n en enero de 1940, durante las ceremonias y festejos organizados por el râ”œآ®gimen franquista con motivo del "XIX centenario de la Virgen del Pilar" en el denominado "Santuario de la Raza".', 1973, 1973, 1973, 'Anos 70', 'CASCO HISTâ”œأ´RICO', 41.65684800, -0.87858500, '0101000020E61000007632384A5E1DECBFB438639813D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27322103815.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27322103815.webp', 'https://www.flickr.com/photos/zaragozaantigua/27322103815/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
